import{t as e}from"./rolldown-runtime-H_PjY6_i.js";var i=e({R0001:()=>t,default:()=>a}),t={title:"Process Automation",definition:"Includes but is not limited to automated registration, login, shopping, coupon collection, lottery, and task completion — using unintended application operations to accelerate or schedule specific workflows.",description:"There are two mainstream approaches to implementing process automation: one is to reverse-engineer the business workflow and data transmission protocol, then write automated scripts to send requests; the other is to manipulate the business access terminal (e.g., browser, mobile app) and replay pre-recorded workflow actions.",complexity:"Advanced",influence:"Exploits platform promotional benefits and occupies resources intended for legitimate users.",references:[{title:"OWASP Automated Threat: OAT006 Expediting"}],keywords:["Process Automation","workflow automation","task automation","automation bot","scripted user actions","OAT-006 Expediting","expediting"]},a={R0001:t,"R0001-001":{title:"Protocol-Level Automation",definition:"Refers to programs that automatically send network protocol requests.",description:"By reverse-engineering the business workflow and data transmission protocol, automated scripts are written to send requests.",complexity:"Advanced",influence:"Exploits platform promotional benefits and occupies resources intended for legitimate users.",references:[{title:"OWASP Automated Threat: OAT-011 Scraping"}],keywords:["Protocol-Level Automation","API automation","request automation","protocol bot","direct API calls","HTTP request scripting","headless automation"]},"R0001-002":{title:"Automated Simulator",definition:"Refers to simulator programs that mimic normal user behavior to automatically send network protocol requests.",description:"By manipulating the business access terminal (e.g., browser, mobile app), pre-recorded workflow actions are replayed repeatedly.",complexity:"Advanced",influence:"Exploits platform promotional benefits and occupies resources intended for legitimate users.",references:[{title:"OWASP Automated Threat: OAT-020 Account Aggregation"}],keywords:["Automated Simulator","UI automation","client automation","device farm bot","click bot","emulator farm","RPA bot"]}},n=e({R0002:()=>o,default:()=>s}),o={title:"Coupon Enumeration",definition:"Bulk enumeration of coupon codes, redemption codes, discount codes, and other promotional voucher credentials.",description:"Voucher numbers are generated by some rule-based sequence or guessable algorithm. Through brute-force enumeration or algorithm cracking, voucher numbers can be obtained in bulk for further exploitation.",complexity:"Basic",influence:"Exploits platform promotional benefits and occupies resources intended for legitimate users.",references:[{title:"OWASP Automated Threat: OAT002 Token Cracking"}],keywords:["Coupon Enumeration","coupon code brute force","voucher brute force","promo code guessing","voucher cracking","code enumeration","OAT002 Token Cracking"]},s={R0002:o},r=e({R0003:()=>c,default:()=>l}),c={title:"Malicious Flash Sale Grabbing",definition:"Using automated means to grab goods or services during flash sales.",description:"Also known as malicious order snatching. Refers to bad actors using technical means such as purchase-grabbing software to maliciously snatch time-limited, limited-quantity discounted goods on e-commerce platforms, disrupting normal market order and consumer shopping experience. These tools simulate human operations such as login, clicking, and order submission to achieve automated purchasing.",complexity:"Intermediate",influence:"Exploits platform promotional benefits, disrupts normal platform operations, and degrades the ordering and shopping experience for legitimate users.",references:[{title:"制作、销售货拉拉外挂4人获刑 货拉拉:超2万司机因使用外挂被封号..."}],keywords:["Malicious Flash Sale Grabbing","flash sale bot","purchase bot","scalping bot","drop bot","auto checkout bot","order snatching"]},l={R0003:c,"R0003-001":{title:"Instant Bid Sniping",definition:"Placing a bid at the first possible moment to obtain limited or flash-sale goods or services through unfair means.",description:"Using unfair methods to obtain limited or flash-sale goods, services, or discounts — typically via third-party scripts or auxiliary tools. Sometimes relies on third-party intelligence to pre-leak interface information. Usually requires process automation capabilities (R0001).",complexity:"Intermediate",influence:"Exploits platform promotional benefits and disrupts legitimate user ordering.",references:[{title:"OWASP Automated Threat: OAT005 Scalping"}],keywords:["Instant Bid Sniping","instant snipe bot","first-bid automation","purchase sniping","drop sniping","buyout bot"]},"R0003-002":{title:"Auction Sniping",definition:"Placing a bid on goods or services at the last minute.",description:"Using automated means to place a bid at the last minute, often completing a transaction at minimal cost. The principle is the same as instant bid sniping (R0003) but the goal differs: auction sniping aims to be the last valid bid before the deadline to obtain goods at the lowest possible price, while instant bid sniping aims to be the first bid after the sale starts to secure limited discounted items. Auction sniping typically requires process automation (R0001).",complexity:"Intermediate",influence:"Transaction prices are too low, resulting in insufficient profit margins. Disrupts legitimate user ordering.",references:[{title:"OWASP Automated Threat: OAT013 Sniping"}],keywords:["Auction Sniping","auction sniper","sniping bot","last-second bidding","bid sniper","eBay sniping"]},"R0003-003":{title:"Bot Scalping Risk",definition:"Bots refer to the practice of seizing, misappropriating, or manipulating scarce resources through illegitimate means, especially using automated crawler techniques.",description:"Using automated scripts or crawler tools to register large numbers of fake accounts, simulating transaction activity and fictitious purchases to seize scarce resources on the platform — such as limited-edition goods or purchase eligibility — preventing legitimate users from having a fair chance.",complexity:"Intermediate",influence:"Disrupts legitimate user ordering.",references:[{title:"Measures for the Supervision and Administration of Online Transactions",link:"https://www.moj.gov.cn/pub/sfbgw/flfggz/flfggzbmgz/202104/t20210423_357848.html"}],keywords:["Bot Scalping Risk","scalper bot","grabbing bot","inventory scalping","limited-drop bot","mass purchase bot","OAT-005 Scalping"]},"R0003-004":{title:"Unfair Resource Seizure",definition:"Unfair resource seizure risk refers to individuals or organizations using illegitimate means to compete for and seize limited resources, violating fair competition principles and potentially causing unfair resource distribution and system abuse.",description:"Specific illegitimate means include but are not limited to: using bot programs to rapidly submit large numbers of requests the moment resources become available; using malicious software to attack target systems; exploiting system vulnerabilities to bypass normal allocation mechanisms; submitting false personal or application information to deceive the system.",complexity:"Intermediate",influence:"May lead to unfair resource distribution, system overload, and escalating malicious competition.",references:[{title:"OWASP Automated Threat: OAT-021 Denial of Inventory"}],keywords:["Unfair Resource Seizure","resource grabbing","slot grabbing","inventory hoarding","eligibility hoarding","automated resource seizure","denial of inventory"]}},d=e({R0004:()=>u,default:()=>p}),u={title:"Fake Shipment",definition:"Fake shipment refers to a merchant or individual who, knowing that goods have not actually been shipped, deliberately provides false shipping information to the buyer in order to deceive or evade responsibility.",description:"Fake shipment is one of the common fraud tactics in e-commerce or offline transactions. It typically involves: hiding the true status of goods (e.g., damaged, out of stock, or delayed); evading responsibility by sending unrelated items or empty packages after payment; substituting low-quality goods to reduce costs; or making false promises through misleading promotional tactics.",complexity:"Basic",influence:"Damages buyers' legitimate rights and interests and disrupts normal platform operations.",references:[{title:"网络交易监督管理办法",link:"https://www.moj.gov.cn/pub/sfbgw/flfggz/flfggzbmgz/202104/t20210423_357848.html"}],keywords:["Fake Shipment","false shipment","fake tracking number","empty box scam","false fulfillment","phantom shipping","shipment fraud"]},p={R0004:u},m=e({R0005:()=>g,default:()=>f}),g={title:"Promotional Activity Cheating",definition:"Using large numbers of accounts to complete platform promotional activities for profit.",description:"After obtaining a large number of platform accounts, automatically completing platform promotional activities (including check-ins, tasks, red packet grabbing, coupon collection, flash sales, group buying, etc.). Account sources typically include bulk registration by black market operators (R0030), credential stuffing (R0032-001), credential cracking (R0032), or purchasing from black markets. Completing activities requires process automation capabilities (R0001).",complexity:"Intermediate",influence:"Exploits platform promotional benefits and prevents legitimate users from participating in activities.",references:[{title:"What Does Promotional Activity Cheating Mean?"}],keywords:["Promotional Activity Cheating","promo abuse","promotion abuse","campaign abuse","activity farming","incentive abuse","bonus abuse"]},f={R0005:g,"R0005-001":{title:"Bulk Fake Account Manipulation",definition:"Using large numbers of accounts to perform likes, favorites, shares, comments, etc. to influence platform ranking metrics and profit.",description:"After obtaining a large number of platform accounts, automatically performing likes, favorites, shares, comments, and other functions to influence platform ranking metrics, enabling unfair competition and profit. Account sources typically include bulk registration (R0030), credential stuffing (R0032-001), credential cracking (R0032), or purchasing from black markets. Requires process automation capabilities (R0001).",complexity:"Advanced",influence:"Enables unfair competition through inflated positive ratings.",references:[{title:"What Is the Purpose of Fake Followers? How to Remove Fake Followers?"}],keywords:["Bulk Fake Account Manipulation","engagement fraud","bulk account farming","fake engagement","like farm","comment farm","account farm"]},"R0005-002":{title:"Fake Viral Referral",definition:"Using large numbers of accounts to complete referral/viral growth activities for profit.",description:"Also called 'new user acquisition cheating'. After obtaining a large number of platform accounts, automatically completing referral and recommendation tasks for profit. Account sources typically include bulk registration (R0030). Requires process automation capabilities (R0001).",complexity:"Advanced",influence:"Exploits platform promotional benefits.",references:[{title:"Governance Path for Advertising-Promotion Cyber Black-Grey Crime"},{title:"Running a Viral Marketing Campaign? Don't Overlook the Anti-Cheating Component"}],keywords:["Fake Viral Referral","referral fraud","invite fraud","referral farming","new user acquisition fraud","invite bot","referral abuse"]}},h=e({R0006:()=>y,default:()=>b}),y={title:"False Advertising",definition:"False advertising refers to the practice in commercial activities where operators use advertisements or other methods to make false statements about goods or services that do not match actual content, causing customers or consumers to be misled.",description:"False advertising commonly involves: exaggerating product performance or effects; fabricating customer reviews or usage experiences; marking up prices then offering fake discounts; fabricating sales volumes to create a false impression of popularity; inventing scientific research or data to lend credibility; hiding additional fees; using fraudulent certification labels or awards; making unfair or inaccurate comparisons with competitors; using misleading images or advertisements; and deliberately concealing product defects.",complexity:"Basic",influence:"Consumers are misled into believing products have official endorsements or superior performance, affecting their purchasing decisions.",references:[{title:"Anti-Unfair Competition Law of the People's Republic of China"}],keywords:["False Advertising","misleading advertising","deceptive marketing","bait advertising","fake claims","ad misrepresentation","truth-in-advertising violation"]},b={R0006:y},k=e({R0007:()=>v,default:()=>w}),v={title:"Unauthorized Plugin Promotion",definition:"Conducting promotions through plugin-type applications or plugins attached to application clients.",description:"Unauthorized promotional plugins can be implemented in three modes: as an add-on attached to a browser or application client; by hijacking traffic on the access terminal and intercepting/redirecting specific traffic; or as a third-party tool or website (e.g., price comparison or cashback sites) conducting illegal promotions.",complexity:"Advanced",influence:"Causes economic losses to the platform and customer attrition.",references:[{title:'Rule Guide: Interpretation of Rules on "Unauthorized Plugin Promotion"'}],keywords:["Unauthorized Plugin Promotion","affiliate toolbar","promo extension abuse","browser extension promotion","toolbar hijacking","unauthorized affiliate plugin","shopping assistant plugin"]},w={R0007:v,"R0007-001":{title:"Third-Party Price Comparison",definition:"While a user is browsing a normal product detail page, providing price comparisons for the same product from competing websites.",description:"Typical unauthorized promotional plugins exist as browser extensions, as well as app add-on plugins. While reasonable price comparison benefits market activity and saves consumer spending, incomplete or intentionally biased comparisons can cause economic losses or customer attrition — for example, comparing different brands, different models, or different service tiers.",complexity:"Advanced",influence:"Causes economic losses to the platform and customer attrition.",references:[{title:"Chrome Extensions Documentation",link:"https://developer.chrome.com/docs/extensions"}],keywords:["Third-Party Price Comparison","price comparison extension","shopping comparison plugin","comparison toolbar","price checker plugin","affiliate comparison widget"]},"R0007-002":{title:"Access Link Hijacking",definition:"Hijacking users' normal access requests and illegally redirecting them to other sites, cashback pages, or promotional pages.",description:"Using viruses, trojans, malicious plugins, unauthorized bundled software, forced homepage setting, browser hijacking, page hijacking, search engine manipulation, or user information tampering to hijack normal traffic. Or during normal browsing, hijacking website traffic by modifying URL parameters or using pop-ups/floating windows.",complexity:"Advanced",influence:"Causes economic losses to the platform and customer attrition.",references:[{title:"Software Extensions, Technique T1176 - MITRE ATT&CK",link:"https://attack.mitre.org/techniques/T1176/"}],keywords:["Access Link Hijacking","link hijacking","affiliate hijacking","URL hijack","browser redirect hijack","traffic hijack","link interception"]},"R0007-003":{title:"Unauthorized Promotional Redirection",definition:"While a user is browsing a normal product detail page, providing information that induces the user to purchase from another page.",description:"Typical unauthorized promotional plugins exist as browser extensions, as well as app add-on plugins. The main tactic is to present more attractive or better-value product information when a user views a product, or to guide users to download a client through cashback or commission-sharing schemes.",complexity:"Advanced",influence:"Causes economic losses to the platform and customer attrition.",references:[{title:"Chrome Extensions Documentation",link:"https://developer.chrome.com/docs/extensions"}],keywords:["Unauthorized Promotional Redirection","promo redirect","forced affiliate redirect","shopping redirect","traffic redirection","commission redirection","offer redirect"]},"R0007-004":{title:"Unauthorized Plugin Cashback",definition:"While a user is browsing a normal product detail page, the plugin label displays cashback information for that product.",description:"Typical cashback plugins exist as browser extensions, as well as app add-on plugins and third-party apps or websites. The main tactic is to obtain the affiliate commission for a product when a user views it, then share a portion of that commission back to the user as cashback.",complexity:"Advanced",influence:"Causes economic losses to the platform and customer attrition.",references:[{title:"Chrome Extensions Documentation",link:"https://developer.chrome.com/docs/extensions"}],keywords:["Unauthorized Plugin Cashback","cashback extension","rebate plugin","shopping rebate app","commission sharing plugin","affiliate cashback","cashback toolbar"]}},R=e({R0008:()=>A,default:()=>x}),A={title:"Ad Fraud",definition:"Manipulating digital advertising through fake clicks or impressions, or maliciously consuming advertising resources.",description:"Forging or maliciously consuming click counts or impression counts for advertising projects, causing financial losses to advertisers. This generally involves ad network fraud or malicious actions by competitors. Ad network fraud typically includes inflating click or impression counts. Competitors typically maliciously click links to exhaust advertising budgets, increasing total advertiser spend.",complexity:"Basic",influence:"Financial losses to advertisers.",references:[{title:"OWASP Automated Threat: OAT003 Ad Fraud"}],keywords:["Ad Fraud","invalid traffic","IVT","media fraud","advertising fraud","ad spend abuse","traffic fraud","OAT-003"]},x={R0008:A,"R0008-001":{title:"Ad Link Hijacking",definition:"Tampering with advertising links to change the ultimate beneficiary of the ad promotion.",description:"Using browser plugins or applications to hijack product links or ad links, converting a user's direct product visit into a visit through an affiliate promotion link to earn commissions. Or hijacking and tampering with existing affiliate promotion links to change the ultimate beneficiary and intercept commissions.",complexity:"Intermediate",influence:"Financial losses to advertisers or affiliate promoters.",references:[{title:"Software Extensions, Technique T1176 - MITRE ATT&CK",link:"https://attack.mitre.org/techniques/T1176/"}],keywords:["Ad Link Hijacking","affiliate link hijacking","commission hijacking","link rewriting","affiliate theft","attribution hijack"]},"R0008-002":{title:"Click Fraud",definition:"Click fraud refers to artificially generated fake click behavior through fraudulent means, typically occurring in the digital advertising space.",description:"This behavior is designed to mislead advertising systems into recording fictitious ad click counts to obtain improper revenue or inflate ad performance metrics. Fake clicks may be generated through automated scripts, bots, click farms, and similar means rather than genuine user intent.",complexity:"Intermediate",influence:"May cause harm to advertisers, ad platforms, and the entire digital advertising ecosystem.",references:[{title:"OWASP Automated Threat: OAT-003 Ad Fraud"}],keywords:["Click Fraud","fake clicks","PPC fraud","pay-per-click fraud","click bot","click farm","invalid clicks"]},"R0008-003":{title:"Fake App Installs",definition:"Fake installs refer to fraudulently simulating or faking user installation behavior for an application or software to obtain false install counts or active user numbers.",description:"Fake install methods include using automated scripts, bots, or virtual accounts to simulate large numbers of user installs, or using other technical means to generate large volumes of fake app install records in a short time. This can cause app stores and advertisers to misjudge the true value and popularity of an app.",complexity:"Intermediate",influence:"Financial losses to advertisers or affiliate promoters.",references:[{title:"OWASP Automated Threat: OAT-003 Ad Fraud"}],keywords:["Fake App Installs","install fraud","mobile install fraud","fake CPI installs","app install bot","install farm","attribution fraud"]},"R0008-004":{title:"Impression Fraud",definition:"Charging impression fees for ad materials that have not generated exposure or have not completed valid exposure.",description:"For example, a media outlet places multiple display ads in the same ad slot and charges the advertiser for multiple ad impressions.",complexity:"Intermediate",influence:"Financial losses to advertisers.",references:[{title:"OWASP Automated Threat: OAT-003 Ad Fraud"}],keywords:["Impression Fraud","impression stuffing","view fraud","display ad fraud","fake impressions","ad stacking","impression inflation"]},"R0008-005":{title:"Traffic Attribution Fraud",definition:"A cheating method targeting CPA/CPS traffic that disguises organic traffic as channel traffic to obtain channel traffic commissions.",description:"Fraudulent ad channel operators collect large amounts of device and user information, then directly send click information from different devices to the advertiser's ad click log server. If some organic traffic happens to convert within a certain time window, the activation log server records the corresponding device activation and attributes it to the fraudulent channel operator. This method of sending false information to disguise organic traffic as channel traffic can be applied at many stages, such as faking server click behavior or faking tracking code events.",complexity:"Advanced",influence:"Financial losses to advertisers or affiliate promoters.",references:[{title:"OWASP Automated Threat: OAT-003 Ad Fraud"}],keywords:["Traffic Attribution Fraud","attribution fraud","click injection","click spamming","organic hijacking","last-click hijack","CPA fraud"]}},C=e({R0009:()=>S,default:()=>I}),S={title:"Malicious Benefit Abuse",definition:"Malicious benefit abuse (coupon abuse) refers to obtaining illegitimate gains by excessively exploiting merchant promotional policies or activities.",description:"Merchants run coupon collection, points, discounts, rebates, and giveaway activities to attract new users, boost sales, or increase user engagement. Malicious benefit abuse refers to attackers exploiting loopholes in merchant activities — including but not limited to: quantity limit failures, time limit failures, and eligibility restriction failures — to excessively (often through automated means) obtain more benefits, causing significant financial losses to merchants.",complexity:"Basic",influence:"Causes significant financial losses to platforms and merchants.",references:[{title:"2024 H1 Internet Black-Grey Industry Research Report"}],keywords:["Malicious Benefit Abuse","coupon abuse","promo abuse","offer abuse","bonus abuse","discount abuse","incentive abuse"]},I={R0009:S},T=e({R0010:()=>P,default:()=>M}),P={title:"Unauthorized Third-Party Top-Up Services",definition:"Providing low-price top-up services that bypass official legitimate recharge channels.",description:"Obtaining low-cost top-up resources through promotional, non-compliant, or illegal means, and offering top-up services externally.",complexity:"Basic",influence:"Affects the normal operations and profitability of game operators.",references:[{title:"Crackdown on Cyber Black-Grey Market: Putuo Prosecution Recovers 100 Million in Proxy Recharge Case"}],keywords:["Unauthorized Third-Party Top-Up Services","gray-market top-up","proxy recharge","unofficial recharge","third-party recharge","cheap top-up","recharge arbitrage"]},M={R0010:P},B=e({R0011:()=>F,default:()=>O}),F={title:"Account Reselling",definition:"Account reselling refers to individuals or organizations obtaining large numbers of internet platform accounts through illegal means and then trading them for sale.",description:"These accounts can be from social media, email, online games, e-commerce, and other internet services. Account resellers typically obtain accounts through various means including illegal hacking, malware attacks, and social engineering. Once obtained, they sell them to buyers on the dark web or specific online forums.",complexity:"Intermediate",influence:"Disrupts normal platform operations. Poses threats to user privacy and security, and may lead to account abuse, information leakage, and identity theft.",references:[{title:"Valid Accounts - MITRE ATT&CK T1078"}],keywords:["Account Reselling","account marketplace","stolen account sales","account trafficking","account shop","aged accounts","credentials for sale"]},O={R0011:F,"R0011-001":{title:"Game Account Reselling",definition:"Reselling stolen accounts or game accounts containing special resources.",description:"Reselling stolen game accounts or game accounts containing special resources to convert virtual assets into cash.",complexity:"Basic",influence:"Affects the normal operations and profitability of game operators.",references:[{title:"Shanghai's First Batch Game Account Registration Case: Is Mass Account Creation Illegal?"}],keywords:["Game Account Reselling","game account trading","account flipping","leveled account sales","boosted account sale","RMT accounts"]},"R0011-002":{title:"Account Privilege Reselling",definition:"Paid privilege reselling refers to individuals or organizations obtaining paid services, privileges, or entitlements through illegal means and then reselling them to others.",description:"This may include obtaining paid software, membership accounts, subscription services, or special permissions through malicious means, then selling them to others at a lower price or through illegally obtained channels.",complexity:"Basic",influence:"Causes economic losses to legitimate users and service providers.",references:[{title:"Valid Accounts - MITRE ATT&CK T1078"}],keywords:["Account Privilege Reselling","subscription sharing resale","membership resale","premium account resale","entitlement resale","shared premium accounts","privilege arbitrage"]}},D=e({R0012:()=>z,default:()=>q}),z={title:"Cheating Tools / Game Hacks",definition:"Cheating tools refer to illegal programs or script code used in computer games or software, designed to give users unfair advantages or modify program functionality.",description:"Generally includes: cheat programs providing capabilities beyond normal gameplay such as auto-aim and wall hacks; automation scripts that automatically perform specific tasks like resource collection or quest completion without player involvement; and speed hacks that modify game speed to allow faster movement or actions.",complexity:"Intermediate",influence:"Disrupts the normal operating logic of the application, thereby affecting normal platform operations.",references:[{title:"NetClean 2025 | Police Crack Down on Game Cheat Tools"}],keywords:["Cheating Tools / Game Hacks","game cheats","cheat client","hack tool","trainer","mod menu","aimbot","wallhack"]},q={R0012:z,"R0012-001":{title:"Red Packet Grabbing Bot",definition:"Using cheating tools/scripts to automatically grab red packets in a fraudulent manner.",description:"Mainly used in red packet features of social apps or games such as WeChat and QQ. These tools help users grab red packets the moment they are sent, typically by monitoring chat records and auto-clicking. When a red packet is detected, the tool immediately clicks to grab it at a speed far exceeding human capability.",complexity:"Intermediate",influence:"Undermines platform fairness and disrupts normal user activity order.",references:[{title:"Old Wine in New Bottles: Accessibility Service Abuse by Mobile AI Agents and Unfair Competition"}],keywords:["Red Packet Grabbing Bot","red envelope bot","hongbao bot","auto red packet","packet sniping bot","WeChat red packet bot"]},"R0012-002":{title:"Game Cheating Software",definition:"Game cheating software refers to illegal software or scripts used in video games to gain unfair advantages, modify game content, or manipulate game rules.",description:"Includes: cheat programs providing capabilities beyond normal gameplay such as auto-aim, wallhacks, and infinite lives; scripts and macros that automatically execute specific operations like auto-casting or auto-resource collection; speed hacks; external modifiers that change game files or memory data; and gold/item generators that create fake in-game currency or items.",complexity:"Intermediate",influence:"Undermines game fairness and in-game economies, harms legitimate player experience, and may cause account, item, and platform revenue losses.",references:[{title:"Shanghai Pudong Dismantles Illegal Game Account Sales Gang"}],keywords:["Game Cheating Software","aimbot","wallhack","ESP hack","macro cheat","speed hack","memory editor","mod menu"]}},U=e({R0013:()=>W,default:()=>L}),W={title:"Ad Blocking",definition:"Preventing advertisements from displaying on web pages or applications.",description:"Free content providers typically insert ads into content or before content viewing to generate revenue. Ad blockers typically exist as browser plugins or applications that block ad display, reducing the impact of ads on content viewers or allowing viewers to skip ads and access free content directly. While this improves the viewer experience, from the content operator's perspective, providing free content without earning revenue affects the stability and sustainability of free content provision.",complexity:"Intermediate",influence:"Revenue loss for content providers.",references:[{title:"Governance Path for Advertising-Promotion Cyber Black-Grey Crime"}],keywords:["Ad Blocking","ad blocker","content blocking","ad filtering","anti-ad plugin","banner blocker","pre-roll blocker"]},L={R0013:W},E=e({R0014:()=>G,default:()=>H}),G={title:"Inventory Denial",definition:"Exhausting the inventory of goods or services without completing a purchase or transaction.",description:"By placing large numbers of orders without paying, driving all products in a merchant's store to zero inventory so the merchant has nothing to sell. Additionally, bulk adding items to cart or placing unpaid orders can be used to probe a merchant's inventory levels or actual purchase prices. While not necessarily aimed at exhausting inventory, the harm caused is the same or greater.",complexity:"Basic",influence:"Common in commercial competition. Once inventory is exhausted, other users can no longer purchase the goods.",references:[{title:"OWASP Automated Threat: OAT021 Denial of Inventory"}],keywords:["Inventory Denial","denial of inventory","cart hoarding","cart stuffing","inventory hoarding","stock locking","reservation abuse"]},H={R0014:G},j=e({R0015:()=>N,default:()=>V}),N={title:"Malicious Negative Reviews",definition:"Using false reviews to damage the reputation of a person or product.",description:"Using malicious comments, reviews, ratings, reports, or downvotes to damage the reputation, score, or credibility of other users or merchants.",complexity:"Basic",influence:"Similar to black market metric manipulation (R0016) but different in nature. Metric manipulation has generally become an illegal commercial activity where operators inflate ratings for profit. Malicious reviews, however, are motivated by the intent to damage other users' or merchants' reputation and credibility — typically driven by pure malice or competitive business motives.",references:[{title:"OWASP Automated Threat: OAT016 Skewing"}],keywords:["Malicious Negative Reviews","review bombing","negative review attack","fake bad reviews","rating sabotage","reputation attack","review extortion"]},V={R0015:N},K=e({R0016:()=>Q,default:()=>_}),Q={title:"Metric Manipulation / Ranking Fraud",definition:"Interfering with certain application metrics by repeatedly clicking links, sending requests, or submitting forms.",description:"Automatically and repeatedly clicking, requesting, or submitting content to influence application-based metrics such as frequency and/or rate counts and measurements. Includes ranking fraud, like farming, comment farming, etc. Metrics may be visible to users (e.g., betting odds, likes, market/dynamic pricing, visitor counts, vote results, reviews) or hidden (e.g., application usage statistics, business performance metrics).",complexity:"Basic",influence:"Causes platform display results to lose objectivity and fairness, degrading user experience.",references:[{title:"OWASP Automated Threat: OAT016 Skewing"}],keywords:["Metric Manipulation / Ranking Fraud","ranking manipulation","engagement fraud","metric gaming","skewing","social proof fraud","vote manipulation"]},_={R0016:Q,"R0016-001":{title:"Fake Viewer Count Inflation",definition:"Using illegitimate means or software to artificially inflate the visitor count of a live stream room or personal space, creating a false impression of high traffic, ultimately influencing platform recommendation algorithms.",description:"Also called 'fake audience' or 'ghost viewers'. Typically refers to using software, bots, or crowdsourcing to artificially increase metrics such as page views, likes, comments, and online viewer counts for a web page or live stream room, thereby influencing the platform's scoring and recommendation or ranking of that space.",complexity:"Intermediate",influence:"Undermines platform fairness and interferes with ranking algorithms.",references:[{title:"Methods and Strategies for Inflating TikTok Live Stream Viewer Counts"}],keywords:["Fake Viewer Count Inflation","viewbotting","viewer bot","fake audience","ghost viewers","live view inflation","stream view bot"]},"R0016-002":{title:"Bulk Following",definition:"Using illegitimate means or software to bulk-follow other users, ultimately influencing platform recommendations.",description:"Also called 'mass following'. Typically refers to using software, bots, or crowdsourcing to have a user bulk-follow other users, thereby influencing the platform's scoring and recommendation or ranking of that user.",complexity:"Intermediate",influence:"Undermines platform fairness and interferes with ranking algorithms.",references:[{title:"OWASP Automated Threat: OAT-016 Skewing"}],keywords:["Bulk Following","mass following","follow bot","follow farm","bulk follow","follower manipulation","social graph inflation"]}},Y=e({R0017:()=>J,default:()=>X}),J={title:"Fake Transactions",definition:"Obtaining benefits through invalid transactions.",description:"Merchants complete large numbers of fake transactions to obtain platform merchant discounts/rebates, or to inflate product positive review counts at low cost. Methods generally include 'order A, ship B' schemes or directly shipping empty packages.",complexity:"Intermediate",influence:"Exploits platform merchant discounts/rebates. Enables unfair competition through inflated positive ratings.",references:[{title:"Case Study: Operating a Money Laundering Platform for Cyber Black-Grey Market Merchants"}],keywords:["Fake Transactions","fake orders","sham transactions","wash trading","empty package fraud","transaction brushing","order laundering"]},X={R0017:J,"R0017-001":{title:"Order Brushing",definition:"Merchants completing bulk low-cost or fake orders to inflate transaction volume or improve ratings.",description:"Merchants complete large numbers of low-cost transactions to obtain platform merchant discounts/rebates, or to inflate product positive review counts at low cost. Methods generally include hiring buyers or maliciously listing low-value items to complete bulk transactions.",complexity:"Intermediate",influence:"Undermines fair competition principles on the platform; in some cases exploits platform merchant discounts/rebates.",references:[{title:"Interim Provisions on Anti-Unfair Competition in Cyberspace"}],keywords:["Order Brushing","brush orders","sales brushing","fake order farming","transaction inflation","review brushing","merchant boosting"]},"R0017-002":{title:"Subsidy Fraud",definition:"Defrauding platform or government subsidies, rewards, or promotional funds through fabricated transactions, forged data, or other fraudulent means.",description:"Exploiting loopholes in platform subsidy policies to claim subsidy funds that should not be obtained, through methods such as fake transactions, order brushing, or fabricating user activity. Common tactics include: hiring brushers to create fake transaction records; using multiple accounts to repeatedly claim subsidies; running ghost rides or fake orders on ride-hailing or food delivery platforms to defraud subsidies; e-commerce sellers buying from themselves to exploit platform merchant discounts and rebates.",complexity:"Intermediate",influence:"Causes financial losses to platforms and governments, undermines fair competition, and distorts market resource allocation.",references:[{title:"Black Market Big Data: 2025 Global E-Commerce Fraud Risk Research Report"},{title:"Hiring Order Brushers and Recruiting Insiders to Defraud E-Commerce Platform Subsidies: 9-Person Gang Caught"}],keywords:["Subsidy Fraud","promotion subsidy fraud","rebate fraud","incentive fraud","merchant subsidy abuse","fake ride subsidy","bonus fraud"]}},Z=e({R0018:()=>$,default:()=>ee}),$={title:"Search Result Manipulation",definition:"Interfering with search engine results by providing invalid or illegal data.",description:"Boosting the ranking of a keyword by mass-searching it, or creating associations between keywords by mass-searching them together.",complexity:"Intermediate",influence:"Interferes with the fair ranking mechanism of search engine results, or disrupts intelligent suggestions and related results for normal search keywords.",references:[{title:"Search Results Severely Disrupted by SEO Manipulation: Experts Say Google Is Dying"},{title:"Review of 40 Consumer Scandals from 315 Hot Search: Seven Industry Scandals Exposed"}],keywords:["Search Result Manipulation","search ranking manipulation","search spam","query bombing","SEO manipulation","keyword boosting","SERP manipulation"]},ee={R0018:$},ie=e({R0019:()=>te,default:()=>ae}),te={title:"Unauthorized Account Sharing",definition:"Illegally selling or sharing paid account privileges that support multi-device login to others.",description:"Malicious actors exploit the ability to log into accounts on multiple devices simultaneously, selling accounts with paid privileges to multiple people at low prices to profit from the price difference. The platform's multi-device login feature is intended for a single user with multiple devices, not for different users sharing the same privileges. Instead of earning multiple paid subscriptions, the platform earns only one while black market operators profit from the price arbitrage.",complexity:"Basic",influence:"Causes economic losses to the platform.",references:[{title:"Breaking the Account Theft-Breeding-Sale Black Market: Strengthening Legal and Technical Defenses"}],keywords:["Unauthorized Account Sharing","account sharing resale","shared account marketplace","password sharing abuse","multi-user subscription abuse","household bypass","shared premium accounts"]},ae={R0019:te},ne=e({R0020:()=>oe,default:()=>se}),oe={title:"Content Compliance Risk",definition:"User-generated content compliance risk refers to the risk that content created by users on a platform may violate regulations, ethics, or platform policies, potentially leading to legal liability, reputational damage, or other compliance issues.",description:"Causes include: illegal content — users may post content that is illegal, infringing, or involves others' privacy; policy violations — user-generated content may violate platform usage policies such as malicious attacks, hate speech, or obscene content; intellectual property infringement — users may use others' intellectual property without permission; and misinformation — users may deliberately post false or misleading information.",complexity:"Basic",influence:"May lead to legal liability, reputational damage, user loss, advertiser loss, and regulatory risk, negatively impacting the platform's long-term development.",references:[{title:"2024 National Cyberspace Administration Cracks Down on Illegal Online Content"}],keywords:["Content Compliance Risk","UGC compliance","content moderation risk","policy violation content","trust and safety","platform compliance","content governance"]},se={R0020:oe},re=e({R0021:()=>ce,default:()=>le}),ce={title:"Spam Content",definition:"Spam content risk refers to low-quality, fraudulent, or inappropriate content generated on a platform that may violate platform rules, cause user experience issues, and create compliance risks.",description:"Causes of spam content risk include malicious users posting false information, advertising abuse, mass spamming, low-quality comments, as well as inadequate platform oversight and incomplete review mechanisms.",complexity:"Basic",influence:"Spam content risk may lead to degraded user experience, reputational damage to the platform, loss of advertisers and users, and regulatory sanctions, negatively impacting the platform's long-term development.",references:[{title:"OWASP Automated Threat: OAT-017 Spamming"}],keywords:["Spam Content","content spam","spam posts","low-quality spam","comment spam","junk content","spam generation"]},le={R0021:ce},de=e({R0022:()=>ue,default:()=>pe}),ue={title:"Content Infringement",definition:"User-generated content infringement risk refers to the risk that content created by users on a platform may infringe on others' intellectual property rights, including but not limited to copyright, trademark rights, or patent rights, leading to potential legal liability.",description:"The main causes of infringement risk include users using others' text, images, audio/video, and other intellectual property content without authorization, or including content similar to others' trademarks, as well as the platform's failure to effectively monitor and prevent infringing behavior.",complexity:"Basic",influence:"User-generated content infringement risk may lead to legal liability, reputational damage to the platform, harm to rights holders' interests, and loss of users and advertisers, negatively impacting the platform's long-term development.",references:[{title:"Copyright Law of the People's Republic of China"}],keywords:["Content Infringement","copyright infringement","trademark infringement","IP infringement","infringing content","pirated content","rights violation"]},pe={R0022:ue},me=e({R0023:()=>ge,default:()=>fe}),ge={title:"Content Theft",definition:"Refers to the unauthorized or unpermitted use, copying, distribution, or display of text, images, audio/video, and other content created by others.",description:"Content theft has many causes, including lack of original creativity, commercial competition, profit motives, lack of legal awareness, technical convenience, circumventing security measures, lack of ethical standards, and social media sharing culture. Some individuals or organizations may choose to steal others' work to quickly obtain content, and the development of the internet and digital technology has made copying and distributing content increasingly easy.",complexity:"Basic",influence:"If content theft is not identified and penalized in a timely manner, it will undermine the motivation of original content creators, leading to a race to the bottom.",references:[{title:"Copyright Law of the People's Republic of China",link:"https://www.samr.gov.cn/wljys/gzzd/art/2023/art_3ef1e889c1e644d4b65b5f5c7f432386.html"}],keywords:["Content Theft","content scraping","copy-paste theft","content piracy","unauthorized reposting","content cloning","plagiarized content"]},fe={R0023:ge},he=e({R0024:()=>ye,default:()=>be}),ye={title:"Malicious Traffic Diversion",definition:"Malicious traffic diversion through user-generated content refers to attackers tampering with, forging, or abusing user-generated content such as reviews and social shares to deceive users, redirect traffic, or achieve other malicious purposes.",description:"Causes include: fake reviews and ratings to attract user clicks; social media abuse by fabricating fake shares and likes to redirect traffic; fabricating user activity to make certain content appear more popular; comment section abuse by posting false information; and using malicious tags or keywords to boost search rankings for specific content.",complexity:"Basic",influence:"Malicious traffic diversion through user-generated content may lead to fake traffic, economic losses, decreased user trust, brand reputation damage, and negative impacts on community health.",references:[{title:"OWASP Automated Threat: OAT-017 Spamming"}],keywords:["Malicious Traffic Diversion","traffic hijacking","click diversion","review hijacking","SEO spam redirection","malicious redirection","engagement bait diversion"]},be={R0024:ye},ke=e({R0025:()=>ve,default:()=>we}),ve={title:"Malicious User Poaching",definition:"Poaching sponsors, customers, and streamers.",description:"Using comments, private messages, and other means to contact the platform's sponsors, customers, or streamers with the intent of redirecting them to other platforms.",complexity:"Basic",influence:"Disrupts normal platform operations, exposes users to fraud risks, and negatively impacts the company's normal operations.",references:[{title:"Governance Path for Advertising-Promotion Cyber Black-Grey Crime"}],keywords:["Malicious User Poaching","user poaching","customer poaching","streamer poaching","off-platform solicitation","deal stealing","sponsor poaching"]},we={R0025:ve},Re=e({R0026:()=>Ae,default:()=>xe}),Ae={title:"Prohibited and Illegal Products",definition:"Merchants listing invalid, malicious, or illegal product content.",description:"Merchants list invalid, malicious, or illegal product content to sell non-compliant or illegal goods, or to achieve purposes such as defamation, disruption, traffic diversion, or fraud.",complexity:"Basic",influence:"Disrupts normal system operations, exposes users to fraud risks, and creates compliance risks for the company's normal operations.",references:[{title:"What Are Prohibited Products on Taobao?"}],keywords:["Prohibited and Illegal Products","prohibited items","banned goods","illegal listings","restricted products","contraband sales","non-compliant goods"]},xe={R0026:Ae},Ce=e({R0027:()=>Se,default:()=>Ie}),Se={title:"Web Scraping Risk",definition:"Scraping data provided by an application (product details, prices, inventory, reviews, etc.) for subsequent use. Scraping may occur in real time or more periodically.",description:"Collecting accessible data and/or processed output from an application. Some scraping may use fake or stolen accounts, or access information without authentication. Scraping tools collect responses from static web pages/API interfaces and extract data from them, or decompile apps to parse static resources.",complexity:"Intermediate",influence:"Scraped business data may not cause actual losses to a company until it reaches a certain scale, but once scraped data reaches sufficient scale, it can be used for commercial competition or to analyze company operations in detail, causing significant business harm — for example, analyzing GMV or specific user groups.",references:[{title:"OWASP Automated Threat: OAT011 Scraping"}],keywords:["Web Scraping Risk","data scraping","screen scraping","content scraping","web crawler abuse","API scraping","data harvesting","OAT-011"]},Ie={R0027:Se},Te=e({R0028:()=>Pe,default:()=>Me}),Pe={title:"Data Exfiltration Risk",definition:"Data exfiltration risk refers to obtaining sensitive data stored in an application through public/non-public interfaces, insider threats, or third-party leaks.",description:"Application interfaces may return data structures beyond what is displayed on the frontend — such as addresses, ID numbers, and phone numbers. Users can access public server interfaces to obtain sensitive data (fuzzy username search, bulk adding users with secondary accounts), interact with other users to obtain sensitive data (bulk messaging users with secondary accounts), or enumerate IDs to obtain all private data.",complexity:"Intermediate",influence:"Sensitive data leakage typically occurs alongside issues such as unmasked data, privilege escalation vulnerabilities, and unauthenticated interfaces. In the current environment of strict data security regulation, this may cause serious compliance risks.",references:[{title:"500 Million XX User Records Leaked, XX Called In for Regulatory Interview"}],keywords:["Data Exfiltration Risk","data leakage","sensitive data exposure","data theft","bulk data extraction","information disclosure","unauthorized data access","exfiltration"]},Me={R0028:Pe},Be=e({R0029:()=>Fe,default:()=>Oe}),Fe={title:"Denial of Service Risk",definition:"Slowing down or stopping business responses by sending large numbers of requests to a server or exploiting server vulnerabilities.",description:"Also known as DoS. A denial of service attack is when an attacker causes a target machine to stop providing services. Consuming network bandwidth is only a small part of denial of service attacks — any action that causes trouble for the target, suspends services, or crashes the host qualifies as a denial of service attack.",complexity:"Intermediate",influence:"Causes business denial of service and affects user access.",references:[{title:"OWASP Automated Threat: OAT-015 Denial of Service"}],keywords:["Denial of Service Risk","DoS","service disruption","request flooding","resource exhaustion","availability attack","OAT-015"]},Oe={R0029:Fe,"R0029-001":{title:"SMS Resource Exhaustion",definition:"Bulk requesting SMS verification codes and controlling the recipients to exhaust the application's SMS verification code resources while disrupting legitimate users.",description:"Sending SMS verification code requests to the same phone number to cause disruption or denial of service, or sending SMS verification codes to large numbers of phone numbers to exhaust service resources. In cases where the content can be controlled, this can also trigger fraud.",complexity:"Intermediate",influence:"Exhausts platform SMS verification code resources, creates a denial of service attack against the server, and causes disruption and denial of service to specific phone number recipients.",references:[{title:"What to Do When SMS Verification Code Interface Is Under Malicious Attack?"}],keywords:["SMS Resource Exhaustion","SMS bombing","OTP flooding","verification code bombing","SMS flood","OTP exhaustion","SMS abuse"]},"R0029-002":{title:"Resource Exhaustion Attack",definition:"Also known as malicious resource consumption attacks, the goal is to exhaust the target system's resources — such as computing power, storage space, network bandwidth, or other system resources — to paralyze, slow down, or prevent the system from providing normal services.",description:"Possible scenarios include: network bandwidth attacks flooding the target network; compute resource exhaustion through computationally intensive requests; storage resource exhaustion by uploading large volumes of invalid or large files; TCP connection attacks (SYN flood); and database resource attacks through mass database queries.",complexity:"Intermediate",influence:"Causes service unavailability, performance degradation, reliability impact, and financial losses due to malicious resource consumption.",references:[{title:"Governance Path for Advertising-Promotion Cyber Black-Grey Crime"},{title:"OWASP: OAT-015 Denial of Service"}],keywords:["Resource Exhaustion Attack","resource depletion","application-layer DoS","compute exhaustion","bandwidth exhaustion","storage exhaustion","SYN flood"]},"R0029-003":{title:"CC Attack",definition:"Performing a denial of service attack on a system by constructing large numbers of normal business requests.",description:"By analyzing each type of business request and targeting requests that are computationally expensive for the server, sending large numbers of forged requests to saturate all server computing resources.",complexity:"Intermediate",influence:"Causes business denial of service and affects user access.",references:[{title:"OWASP Automated Threat: OAT-015 Denial of Service"}],keywords:["CC Attack","HTTP flood","challenge collapsar","layer 7 DoS","application flood","web request flood","CC flood"]},"R0029-004":{title:"Distributed Denial of Service",definition:"Distributed Denial of Service (DDoS) is a network attack that uses multiple attackers (or multiple attack sources) to simultaneously attack a target system, rendering it unable to provide normal services.",description:"DDoS attacks typically aim to push the target system's network bandwidth, computing resources, or other critical resources to their limits, causing service unavailability. Attack types include: network layer attacks (UDP flood, ICMP flood, SYN/ACK attacks); transport layer attacks (SYN flood); application layer attacks (HTTP request flood, Slowloris); and reflection/amplification attacks.",complexity:"Intermediate",influence:"Causes service unavailability, performance degradation, reliability impact, and financial losses due to resource consumption.",references:[{title:"Understanding and Responding to Distributed Denial-of-Service Attacks - CISA",link:"https://www.cisa.gov/resources-tools/resources/understanding-and-responding-distributed-denial-service-attacks"}],keywords:["Distributed Denial of Service","DDoS","botnet attack","reflection attack","amplification attack","UDP flood","application-layer DDoS"]}},De=e({R0030:()=>ze,default:()=>qe}),ze={title:"Fake Registration",definition:"Registering fake accounts using false identities for subsequent abuse.",description:"Using an application's account registration process to register accounts with false identity data.",complexity:"Intermediate",influence:"These accounts are subsequently abused for generating spam, money laundering, spreading malware, reputation manipulation, pranks, and distorting SEO, reviews, and surveys.",references:[{title:"OWASP Automated Threat: OAT019 Account Creation"}],keywords:["Fake Registration","fake signup","account creation fraud","synthetic registration","spam account creation","identity spoof registration","OAT-019"]},qe={R0030:ze,"R0030-001":{title:"Bulk Account Registration",definition:"Bulk registering accounts for subsequent abuse.",description:"Using an application's account registration process to create accounts in bulk, sometimes also filling in profile information.",complexity:"Advanced",influence:"These accounts are subsequently abused for generating spam, money laundering, spreading malware, reputation manipulation, pranks, and distorting SEO, reviews, and surveys.",references:[{title:"OWASP Automated Threat: OAT019 Account Creation"}],keywords:["Bulk Account Registration","mass registration","account farming","signup bot","bulk signup","account factory","registration bot"]},"R0030-002":{title:"Third-Party Account Risk",definition:"Using third-party account federated login to bypass existing identity verification systems.",description:"Many sites have strict identity verification systems for creating user identities, such as SMS verification codes and real-name authentication. However, when logging in via third-party identity providers like WeChat or Weibo, excessive trust in the third party without strict identity verification allows bulk registration of spam accounts (R0030-001) on the third party to bypass the strict identity verification system.",complexity:"Intermediate",influence:"Bypasses existing identity verification systems, causing defense mechanisms to fail.",references:[{title:"What Is Third-Party Account Login? What Are Its Benefits?"}],keywords:["Third-Party Account Risk","federated login abuse","social login abuse","OAuth abuse","third-party SSO abuse","IdP trust abuse","social signup bypass"]},"R0030-003":{title:"Overseas Number Registration",definition:"Using overseas phone numbers to register accounts and bypass domestic real-name authentication requirements for phone numbers.",description:"Many sites have strict identity verification systems, such as SMS verification codes. However, when registering with overseas phone numbers, excessive trust in overseas numbers without strict identity verification allows bulk registration (R0030-001) of large numbers of spam accounts to bypass the strict identity verification system.",complexity:"Intermediate",influence:"Bypasses existing identity verification systems, causing defense mechanisms to fail.",references:[{title:"Telephone User Real Identity Information Registration Regulations",link:"https://www.moj.gov.cn/pub/sfbgw/flfggz/flfggzbmgz/201311/t20131119_145359.html"}],keywords:["Overseas Number Registration","foreign number signup","international SIM registration","overseas phone registration","cross-border number signup","non-domestic SIM abuse"]},"R0030-004":{title:"Inactive Number Registration",definition:"Inactive number registration refers to using phone numbers that have not been put into market use or activated to falsely register internet platform accounts or conduct other online activities.",description:"Inactive number registration generally exploits vulnerabilities in the registration process for inactive number verification, or uses insiders at companies or carriers to obtain verification codes. This method has zero cost since no physical SIM card is needed, allowing criminals to hide their identities online and massively abuse platform resources for fake follower/metric inflation, spreading false information, and online fraud.",complexity:"Advanced",influence:"Risks mainly manifest in disrupting normal internet order, potential social engineering attacks, challenges from new cybercrime patterns, and economic and reputational impacts on users and platforms.",references:[{title:"Shanghai's First Batch Game Account Registration Case: Is Mass Account Creation Illegal?"}],keywords:["Inactive Number Registration","unused number registration","unactivated SIM signup","dormant number abuse","carrier insider registration","silent number signup"]},"R0030-005":{title:"Virtual Number Registration",definition:"Virtual number registration refers to using virtual phone numbers to falsely register internet platform accounts or conduct other online activities.",description:"Besides the four major carriers, China has many virtual network operators (MVNOs) that purchase voice, SMS, and data services from the major carriers and resell them under their own branding. These are commonly called 'virtual cards' by black market operators. Virtual card number prefixes are fixed (162, 165, 167, 170, 171). Compared to physical SIM cards, virtual cards have two advantages: low cost (often zero monthly fee) and low barrier (one ID card can be used to register dozens of cards across different MVNOs).",complexity:"Basic",influence:"Bulk registration with virtual numbers may lead to online service abuse, including online fraud and false information spreading, damaging platform credibility and user security.",references:[{title:"Notice on Cleaning Up Fraud-Related Phone Cards, IoT Cards, and Associated Internet Accounts",link:"https://www.mps.gov.cn/n6557558/c7942172/content.html"}],keywords:["Virtual Number Registration","virtual SIM signup","MVNO registration abuse","burner number signup","VoIP number registration","virtual phone number abuse"]},"R0030-006":{title:"IoT SIM Card Registration",definition:"IoT SIM card registration refers to using IoT SIM cards to falsely register internet platform accounts or conduct other online activities.",description:"IoT SIM cards are phone cards specifically designed for IoT terminal devices to provide connectivity. By default they do not have SMS sending/receiving capability, which must be applied for at the time of purchase.",complexity:"Basic",influence:"Bulk registration with IoT SIM cards may lead to online service abuse, including online fraud and false information spreading, damaging platform credibility and user security.",references:[{title:"Notice on Cleaning Up Fraud-Related Phone Cards, IoT Cards, and Associated Internet Accounts",link:"https://www.mps.gov.cn/n6557558/c7942172/content.html"}],keywords:["IoT SIM Card Registration","IoT SIM abuse","machine-to-machine SIM signup","M2M SIM registration","data-only SIM abuse","IoT card signup"]},"R0030-007":{title:"Interceptor Card Registration",definition:"An 'interceptor card' refers to a setup where both the card device and the SIM card are in the hands of a legitimate user, but the card vendor has pre-installed a backdoor in the device that can intercept SMS verification codes received by the user's phone.",description:"Interceptor cards require that the legitimate device holder has not registered for the black market operator's target online service, otherwise the black market operator cannot use it for fake registration. To achieve this, interceptor cards primarily target three types of devices: phones exported overseas, low-to-mid-range phones, and children's smartwatches — because users of these devices (overseas users, elderly people, and children) are unlikely to have registered for the target services.",complexity:"Basic",influence:"Fake registration may lead to online service abuse, including online fraud and false information spreading, damaging platform credibility and user security.",references:[{title:"Notice on Cleaning Up Fraud-Related Phone Cards, IoT Cards, and Associated Internet Accounts",link:"https://www.mps.gov.cn/n6557558/c7942172/content.html"}],keywords:["Interceptor Card Registration","SMS interception device","interceptor SIM setup","verification code interception","backdoored handset registration","SMS relay device"]}},Ue=e({R0031:()=>We,default:()=>Le}),We={title:"Sub-Account Abuse",definition:"Business account systems that have a sub-account concept but manage sub-accounts loosely, leading to account abuse.",description:"Some business systems have very strict account registration requirements but are lax about sub-account creation, and sub-accounts have all the same capabilities as the parent account. Black market operators can bypass strict account registration and identity authentication policies by bulk-generating sub-accounts.",complexity:"Intermediate",influence:"Sub-account abuse bypasses account registration and identity authentication policies.",references:[{title:"What Are the Drawbacks and Risks of Taobao Store Sub-Accounts?"},{title:"Alipay Vulnerability Exposed: Multiple Sub-Accounts Linked Without User Knowledge"}],keywords:["Sub-Account Abuse","sub account abuse","bulk sub-account creation","child account abuse","secondary account abuse","sub-account farming"]},Le={R0031:We},Ee=e({R0032:()=>Ge,default:()=>He}),Ge={title:"Account Takeover",definition:"Stealing login credentials through trojans, phishing, and other means.",description:"There are two typical types of login credentials: authentication credentials used to log in (primarily username/password, but also one-time passwords, SMS verification codes, biometric features, etc.); and session maintenance credentials used to maintain login state (typically cookies, but also session IDs, nonces, JSON Web Tokens, etc.).",complexity:"Advanced",influence:"Grants the attacker persistent account access and operational permissions on the corresponding website or application.",references:[{title:"OWASP Automated Threat: OAT007 Credential Cracking"}],keywords:["Account Takeover","ATO","account hijacking","account compromise","stolen account","account theft"]},He={R0032:Ge,"R0032-001":{title:"Credential Stuffing",definition:"Testing the validity of stolen account credentials in the current system through bulk login attempts.",description:"Testing a list of stolen authentication credentials against the current system's authentication mechanism to determine whether users have reused the same login credentials. Stolen usernames (usually email addresses) and passwords may have been obtained directly from another application, purchased on criminal markets, or obtained from publicly available breach data dumps. Unlike credential cracking, credential stuffing does not involve any brute force or numerical guessing.",complexity:"Advanced",influence:"Through unrestricted credential stuffing, attackers may gain access to many users who have reused credentials from other systems, causing losses to those users through further operations.",references:[{title:"OWASP Automated Threat: OAT008 Credential Stuffing"}],keywords:["Credential Stuffing","combo list attack","credential reuse attack","account checker","combo checker","bulk login attempts"]},"R0032-002":{title:"Password Spraying",definition:"Attempting to log in by trying one or a few common weak passwords against a large number of accounts to obtain valid credentials.",description:"Unlike credential brute force which enumerates passwords for a single account, password spraying fixes one or a few common passwords and tries them against a large number of different user accounts to discover accounts using that weak password. This approach avoids triggering account lockout mechanisms that would result from multiple failed attempts on a single account.",complexity:"Advanced",influence:"Through unrestricted credential attacks, attackers may gain access to users with weak passwords on the current system, causing losses through further operations.",references:[{title:"OWASP Automated Threat: OAT007 Credential Cracking"}],keywords:["Password Spraying","password spray","common password attack","low-and-slow password attack","one-password-many-accounts"]},"R0032-003":{title:"Credential Brute Force",definition:"Attempting to log in by brute-forcing a list of possible passwords for a specific account to obtain valid credentials.",description:"Using brute force, dictionary (word list), and guessing attacks against the application's authentication process to identify the weak credentials used by a specific account — for example, enumerating a user's password.",complexity:"Advanced",influence:"Through unrestricted credential attacks, attackers may gain access to users with weak passwords on the current system, causing losses through further operations.",references:[{title:"OWASP Automated Threat: OAT007 Credential Cracking"}],keywords:["Credential Brute Force","password brute force","login brute force","dictionary attack","password guessing"]},"R0032-004":{title:"Verification Code Brute Force",definition:"Attempting to log in by brute-forcing verification codes to obtain valid credentials.",description:"Verification code brute force risk refers to attackers attempting to break verification codes by continuously trying various possibilities to gain access to a system or account. Causes include: weak verification code design; lack of security protections such as frequently changing codes or lockout mechanisms; reuse of the same verification code across multiple locations; and inadequate verification code generation algorithms.",complexity:"Intermediate",influence:"Defeats verification-code protections, allowing attackers to take over accounts, bypass login checks, or trigger subsequent fraud operations.",references:[{title:"Brute Force - MITRE ATT&CK T1110"}],keywords:["Verification Code Brute Force","OTP brute force","SMS code brute force","one-time password brute force","2FA code brute force","verification code guessing"]}},je=e({R0033:()=>Ne,default:()=>Ve}),Ne={title:"Ghost Stores",definition:"Ghost stores refer to stores that exist on physical or online platforms but are effectively closed, abandoned, or unable to operate normally due to poor management, poor operations, poor sales performance, or other reasons.",description:"On online platforms, especially e-commerce platforms, merchants may sometimes stop operating or go long periods without updating products and services, yet their stores remain active. These abandoned or non-functioning stores are sometimes called 'ghost stores'.",complexity:"Basic",influence:"May lead to the store being unable to provide normal services, declining product quality, and potential inability to process returns or provide after-sales service.",references:[{title:"SAMR 2024 Online Market Regulation Campaign"}],keywords:["Ghost Stores","zombie store","abandoned storefront","inactive merchant store","dead store"]},Ve={R0033:Ne,"R0033-001":{title:"Merchant Disappearance / Runaway",definition:"A merchant suddenly becomes unreachable after operating on the platform for a period of time.",description:"Some disappearances may be caused by sudden circumstances or poor management, while others are deliberate — either to evade platform responsibilities or to cold-shoulder buyer complaints.",complexity:"Basic",influence:"May lead to the store being unable to provide normal services, inability to process returns, or lack of after-sales service.",references:[{title:"SAMR Advances 2024 Online Market Supervision Special Action",link:"https://www.samr.gov.cn/wljys/sjdt/art/2024/art_ae31439848ef41e49b43ab0eb923326d.html"}],keywords:["Merchant Disappearance / Runaway","merchant absconding","seller disappearance","merchant runaway","seller absconding","merchant exit scam"]}},Ke=e({R0034:()=>Qe,default:()=>_e}),Qe={title:"Automated Account Seasoning",definition:"Using automated means to improve account credibility.",description:"Using automated activities on stolen accounts or bulk-registered accounts to reduce account risk scores or improve account credibility — for example, automated reviews, comments, posts, and transactions.",complexity:"Advanced",influence:"Automated account seasoning typically needs to be combined with other business risk scenarios to monetize, such as benefit abuse, flash sale grabbing, and metric manipulation.",references:[{title:"OWASP Automated Threat: OAT-019 Account Creation",link:"https://owasp.org/www-project-automated-threats-to-web-applications/assets/oats/EN/OAT-019_Account_Creation.html"}],keywords:["Automated Account Seasoning","account warming","account farming","reputation farming","trust score boosting","account nurturing"]},_e={R0034:Qe},Ye=e({R0035:()=>Je,default:()=>Xe}),Je={title:"Login Credential Reuse",definition:"Copying a user's session credentials (session cookies) to another device to bypass the login process and directly reuse the user's identity.",description:"A common method is to obtain user cookies to enable automated password-free login. Many account vendors sell accounts by providing only login cookies rather than credentials — known as CK trading. CK trading can bypass SMS verification code login and prevents buyers from changing passwords, enabling multiple resales of the same account.",complexity:"Intermediate",influence:"Bypasses MFA multi-factor authentication mechanisms in the login process, or enables a single account to log in on multiple devices.",references:[{title:"Session Hijacking Attack - OWASP",link:"https://owasp.org/www-community/attacks/Session_hijacking_attack"},{title:"Steal Web Session Cookie - MITRE ATT&CK T1539"}],keywords:["Login Credential Reuse","session hijacking","cookie reuse","session cookie reuse","stolen session","session token reuse"]},Xe={R0035:Je,"R0035-001":{title:"Login Credential Theft",definition:"Stealing user identity credentials to impersonate the user's identity for access.",description:"Credential theft is a form of credential reuse. Credential reuse more often refers to a voluntary process of copying and reusing credentials; credential theft refers to a user's identity credentials being stolen by a hacker for use elsewhere to impersonate the user's login.",complexity:"Intermediate",influence:"Many account systems do not invalidate existing login sessions after a password change, meaning that with stolen or reused cookies, a hacker can maintain persistent login access to the target user's account.",references:[{title:"Nearly 1,000 Data Breaches in Q1 2023, Affecting 1,204 Companies Across 38 Industries"},{title:"Credential Stuffing Prevention Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Credential_Stuffing_Prevention_Cheat_Sheet.html"}],keywords:["Login Credential Theft","credential theft","session theft","cookie theft","token theft","account credential theft"]}},Ze=e({R0036:()=>$e,default:()=>ei}),$e={title:"Multi-Factor Authentication (MFA) Bypass",definition:"Cracking or bypassing multi-factor authentication factors during the identity verification process.",description:"Obtaining MFA verification factors through brute force enumeration — such as cracking SMS verification codes, last digits of ID numbers, email verification codes, or OTP tokens; or exploiting flaws in the authentication process — such as forging trusted device fingerprints or requesting non-MFA login pages — to bypass MFA verification.",complexity:"Advanced",influence:"Will bypass existing MFA multi-factor authentication mechanisms, leading to account compromise.",references:[{title:"Exposing Multi-Factor Authentication (MFA) Bypass Techniques"}],keywords:["Multi-Factor Authentication (MFA) Bypass","MFA bypass","2FA bypass","two-factor bypass","OTP bypass","authentication factor bypass"]},ei={R0036:$e,"R0036-001":{title:"MFA Fatigue Attack",definition:"MFA fatigue attack refers to hackers repeatedly sending push notification approval requests after obtaining login credentials, tricking users into granting account access. Eventually, users approve the notification out of fatigue or inattention.",description:"The hacker continuously triggers login approval request push notifications to the victim's device. The victim is initially confused and has about 30% trust. The attacker then uses social engineering to contact the victim, posing as an IT administrator and claiming the system has a problem that requires approving the notification to stop the pushes. The victim's trust rises to about 80% because they believe a real IT admin would know about the issue so quickly and know their name and department. Many employees then comply with the 'fake admin's' instructions.",complexity:"Advanced",influence:"Will bypass existing MFA multi-factor authentication mechanisms, leading to account compromise.",references:[{title:"Nearly 1,000 Data Breaches in Q1 2023, Affecting 1,204 Companies Across 38 Industries"}],keywords:["MFA Fatigue Attack","push bombing","MFA prompt bombing","push fatigue attack","notification fatigue attack","push spam attack"]}},ii=e({R0037:()=>ti,default:()=>ai}),ti={title:"Third-Party Account Aggregation",definition:"Using a third-party application as a proxy to centrally manage account credentials for multiple applications.",description:"Compiling credentials and information from multiple application accounts into another system. A single user can use this aggregation application to consolidate information from multiple applications, or consolidate information from multiple users of a single application — for example, e-commerce migration tools or ticket-grabbing applications.",complexity:"Intermediate",influence:"For users, there is a risk of sensitive information leakage; for the system, there is a risk of platform data loss and increased system request pressure.",references:[{title:"OWASP Automated Threat: OAT020 Account Aggregation"}],keywords:["Third-Party Account Aggregation","account aggregator","account aggregation app","multi-account manager","credential vaulting","account pooling"]},ai={R0037:ti},ni=e({R0038:()=>oi,default:()=>si}),oi={title:"QR Code Login Fraud",definition:"Exploiting the mechanism of mobile app QR code scanning to authorize web login, enabling fraudulent login.",description:"Business mobile apps often support external QR code scanning for app launch and auto-login for convenience and promotion purposes. An attacker only needs to copy the QR code from the business web login page and send it to a victim. Once the victim scans the QR code, the attacker gains web-side account access for the victim.",complexity:"Intermediate",influence:"The user's account is logged into by the attacker.",references:[{title:"Mass QQ Accounts Stolen: QR Code Login Hijacked and Recorded by Black Market Groups"}],keywords:["QR Code Login Fraud","QR login hijacking","QR code phishing","quishing login","QR auth abuse","QR code hijacking"]},si={R0038:oi},ri=e({R0039:()=>ci,default:()=>li}),ci={title:"Negative Public Opinion",definition:"Negative public opinion risk refers to the potential threat to the reputation and image of an individual, organization, brand, or other entity due to the spread of negative information among the public.",description:"This negative information may be true, exaggerated, or even false, but it spreads widely through the internet and social media, potentially causing negative impacts on the affected party. Causes include: false information spreading; social media bombs with large volumes of negative comments flooding in a short time; exposure of misconduct; product or service quality issues; and personal behavior of public figures or executives.",complexity:"Basic",influence:"Harms include reputational damage to individuals, organizations, or brands, potentially leading to loss of trust, business damage, legal issues, and declining employee morale, forcing affected parties to take crisis management and brand maintenance measures.",references:[{title:"Reputation and Its Risks"}],keywords:["Negative Public Opinion","reputation crisis","brand reputation damage","online backlash","adverse publicity","social media outrage"]},li={R0039:ci},di=e({R0040:()=>ui,default:()=>pi}),ui={title:"Carding Attack",definition:"Verifying the validity of stolen payment card credentials through bulk login authentication.",description:"Using a merchant's complete login credential verification process to validate stolen payment cards or accounts. Since the value of stolen accounts is unknown, carding attacks can be used to assess payment card value. The source of credential data may be third-party application breaches, third-party payment channel leaks, or purchases from black markets.",complexity:"Intermediate",influence:"Payment card or account credential information is stolen.",references:[{title:"OWASP Automated Threat: OAT001 Carding"}],keywords:["Carding Attack","carding","card testing attack","credit card testing","payment card testing","stolen card validation","BIN attack"]},pi={R0040:ui},mi=e({R0041:()=>gi,default:()=>fi}),gi={title:"Card Cracking",definition:"Obtaining valid payment information by enumerating different missing start/expiry dates and security codes.",description:"Brute-forcing the start/expiry dates and security codes (CSC) of payment cards, also known as CVN2, CVC, CV2, or CID. The results of a carding attack (R0040) can be used to assess payment card or account value, while the results of card cracking (R0041) can be used for actual payments.",complexity:"Intermediate",influence:"Payment card or account payment information is stolen.",references:[{title:"OWASP Automated Threat: OAT010 Card Cracking"}],keywords:["Card Cracking","CVV brute force","credit card cracking","card security code guessing","expiry date brute force","CVV enumeration"]},fi={R0041:gi},hi=e({R0042:()=>yi,default:()=>bi}),yi={title:"Fake Inventory",definition:"An e-commerce seller deliberately claims to have stock of a product when they do not actually have sufficient inventory.",description:"Fake inventory generally serves a few purposes: first, attracting users with extremely low prices or popular items, then claiming out-of-stock and redirecting users to other products; second, creating fake inventory to attract orders, then fulfilling them through reselling or other means.",complexity:"Basic",influence:"The first type of fake inventory creates a poor shopping experience for users, who may feel deceived; the second type may cause delayed shipments or users paying high prices for low-value goods, negatively impacting user experience.",references:[{title:"How Are Tmall Sellers Penalized for Fake Inventory?"}],keywords:["Fake Inventory","phantom inventory","false stock listing","inventory spoofing","out-of-stock bait","fake stock"]},bi={R0042:yi},ki=e({R0043:()=>vi,default:()=>wi}),vi={title:"Stolen Card Payment",definition:"Using the identity from a stolen payment card or another user's account to complete transactions.",description:"Using the identity from a stolen payment card or another user's account to complete transactions. This is generally used to conceal the attacker's identity or reduce the risk of bulk order fraud being intercepted by risk controls. Login credentials come from carding attacks (R0040), and payment information comes from card cracking (R0041).",complexity:"Advanced",influence:"Payment identity is impersonated.",references:[{title:"Ping An Bank Credit Card Strengthens Tech Empowerment, 'Black Hawk Eye' Deters Financial Black-Grey Market"}],keywords:["Stolen Card Payment","unauthorized card payment","fraudulent card payment","third-party card use","card-not-present fraud","CNP fraud"]},wi={R0043:vi,"R0043-001":{title:"Stolen Card Fraud",definition:"Using funds from a stolen payment card or another user's account to purchase goods or cash out.",description:"Using stolen payment card or account login credentials and payment information to misappropriate or steal funds. In addition to conventional purchases/services/withdrawals, profits can also be made through refunds. Login credentials come from carding attacks (R0040), and payment information comes from card cracking (R0041).",complexity:"Advanced",influence:"Funds in the payment card or account are misappropriated or stolen.",references:[{title:"OWASP Automated Threat: OAT012 Cashing Out"}],keywords:["Stolen Card Fraud","card fraud","credit card fraud","unauthorized purchases","stolen payment method abuse","card-not-present fraud"]}},Ri=e({R0044:()=>Ai,default:()=>xi}),Ai={title:"Transfer Fraud",definition:"Deceiving others into making transfers using high-fidelity spoofed accounts, or forging transfer records.",description:"Typically involves two scenarios: deceiving the payee and deceiving the payer. Deceiving the payee generally involves forging transaction records or using untrustworthy third parties as guarantors. Deceiving the payer generally involves creating high-fidelity spoofed payee accounts to induce payment.",complexity:"Advanced",influence:"Financial loss to the payee or payer.",references:[{title:"Threat Hunter Anti-Money Laundering Intelligence Assists Financial Institutions in Risk Governance"}],keywords:["Transfer Fraud","fake transfer receipt","spoofed payment proof","wire transfer scam","bank transfer fraud","payment confirmation forgery"]},xi={R0044:Ai},Ci=e({R0045:()=>Si,default:()=>Ii}),Si={title:"Points Theft",definition:"Misappropriating non-monetary benefits from a stolen payment card or another user's account.",description:"Using stolen payment card or account login credentials and payment information to misappropriate or steal non-monetary benefits. Login credentials come from carding attacks (R0040), and payment information comes from card cracking (R0041).",complexity:"Advanced",influence:"Non-monetary benefits in the payment card or account are misappropriated or stolen.",references:[{title:"Stealing Mileage Points and Credit Card Fraud: How 'Black Ticket Agents' Operate"},{title:"Li Chen's Mileage Card Fraudulently Used by Over Ten People"}],keywords:["Points Theft","loyalty points theft","reward points theft","points hijacking","account points abuse","loyalty balance theft"]},Ii={R0045:Si,"R0045-001":{title:"Points Redemption Reselling",definition:"An illegal profit-making scheme that uses other people's points for personal gain.",description:"Fraudsters obtain other people's points through various means, then use those points for redemptions, and resell the redeemed gifts or services for profit.",complexity:"Intermediate",influence:"Disrupts market order and infringes on consumer rights.",references:[{title:"Ping An Bank Credit Card Upgrades Black Market Crackdown: 'Black Hawk Eye' Precision Strike"},{title:"Li Chen's Mileage Card Fraudulently Used by Over Ten People"}],keywords:["Points Redemption Reselling","points resale","reward redemption fraud","loyalty resale","redeemed goods reselling","points arbitrage"]}},Ti=e({R0046:()=>Pi,default:()=>Mi}),Pi={title:"Minor Age Verification Bypass",definition:"Bypassing minor identification mechanisms through identity forgery.",description:"Bypassing minor identification mechanisms by using real or forged adult identities, including using adult ID cards, facial recognition, fingerprints, and other biometric data.",complexity:"Intermediate",influence:"Minor identification mechanisms become ineffective.",references:[{title:"Promoting Juvenile Crime Prevention and Governance: SPP Releases Typical Cases"}],keywords:["Minor Age Verification Bypass","underage verification bypass","age gate bypass","minor protection bypass","adult identity borrowing","anti-addiction bypass"]},Mi={R0046:Pi},Bi=e({R0047:()=>Fi,default:()=>Oi}),Fi={title:"CAPTCHA Bypass",definition:"Passing human-machine tests through automated means.",description:"Typically involves passing Turing tests (challenges used to distinguish machines from humans) in an automated manner. In addition to traditional image and audio CAPTCHAs, mini-games or arithmetic challenges may also be used. Commonly used during bulk automated operations to bypass human verification. With the advancement of AI technology, using computer vision and deep learning to automatically recognize CAPTCHAs has become a mainstream attack method. Beyond automated CAPTCHA solving, bypasses can also be achieved by altering the device environment or using third-party scripts to circumvent mouse movement trajectories, touch pressure, 3D gyroscope, and other behavioral biometric checks.",complexity:"Advanced",influence:"Human-machine identification mechanisms become ineffective.",references:[{title:"OWASP Automated Threat: OAT009 CAPTCHA Defeat"}],keywords:["CAPTCHA Bypass","captcha solving","captcha cracking","automated captcha solving","human verification bypass","captcha farm"]},Oi={R0047:Fi},Di=e({R0048:()=>zi,default:()=>qi}),zi={title:"Facial Recognition Bypass",definition:"Bypassing facial recognition by forging or tampering with facial data or related authentication data.",description:"Bypassing facial recognition by forging or tampering with facial data or related authentication data. Common attack techniques include: using deepfake technology to synthesize live facial images, image replacement, injecting custom videos or images into the camera data stream, hijacking the camera or facial recognition app, and tampering with transmission packets. Commonly used in login, payment, and other processes, or as one of the factors in multi-factor authentication.",complexity:"Advanced",influence:"Facial recognition mechanisms become ineffective, leading to unauthorized login, payment, and other risks.",references:[{title:"Face Analysis Technology Evaluation: Presentation Attack Detection - NIST",link:"https://pages.nist.gov/frvt/html/frvt_pad.html"}],keywords:["Facial Recognition Bypass","face unlock bypass","liveness bypass","deepfake face spoofing","presentation attack","face spoofing"]},qi={R0048:zi},Ui=e({R0049:()=>Wi,default:()=>Li}),Wi={title:"Proxy Login / Proxy Order Placement",definition:"Using a device environment to assist logging into another person's account, or using an account to assist others in placing orders.",description:"Using a device environment to assist logging into another person's account, or using an account to assist others in placing orders. Typically done to bypass device risk controls or reduce account risk scores, enabling login, order placement, and other operations.",complexity:"Advanced",influence:"Device/account risk identification mechanisms become ineffective.",references:[{title:"Proxy Ordering Black Market Invades Global E-Commerce: In-Depth Analysis of New Arbitrage and Fraud"}],keywords:["Proxy Login / Proxy Order Placement","account renting","proxy purchasing","assisted order placement","remote account login","account proxying"]},Li={R0049:Wi},Ei=e({R0050:()=>Gi,default:()=>Hi}),Gi={title:"Risk Device Identification Bypass",definition:"Modifying a real device's device information to deceive applications and lower the device risk score.",description:"Scenarios include: the operating system running the app has been rooted, the app runs while being hooked, the app runs under a debugger, or the security certificate between the app and server has been replaced. Common risk device environments also include: injection via Hook frameworks such as Xposed/Frida, app cloning tools, device control systems, and tampering with device fingerprint information.",complexity:"Advanced",influence:"May cause security processes within the application to be broken and data to be forged.",references:[{title:"Cross-Border Fraud Risk: Analysis of Transnational Black-Grey Market Crime Patterns Driven by High Profits"}],keywords:["Risk Device Identification Bypass","device fingerprint spoofing","device ID spoofing","device risk spoofing","root cloaking","environment spoofing"]},Hi={R0050:Gi,"R0050-001":{title:"Virtual Device Identification Bypass",definition:"Simulating a real device through software to facilitate subsequent abuse.",description:"Running applications via cloud phones, cloud servers, virtual machines, emulators, anti-fingerprint browsers, and similar means.",complexity:"Intermediate",influence:"May cause security processes within the application to be broken and data to be forged.",references:[{title:"MASTG-KNOW-0031: Emulator Detection - OWASP",link:"https://mas.owasp.org/MASTG-KNOW-0031/"}],keywords:["Virtual Device Identification Bypass","emulator detection bypass","virtual machine bypass","cloud phone bypass","anti-detect browser","device emulation spoofing"]}},ji=e({R0051:()=>Ni,default:()=>Vi}),Ni={title:"Application Reverse Engineering",definition:"Restoring an application's source code or runtime logic through reverse engineering.",description:"For web applications, WeChat mini-programs, and Android apps, source code can be directly or easily restored, exposing all application processing logic. For iOS apps, reverse analysis can be performed using tools such as class-dump, Hopper, and IDA. When security policies are implemented on the client side, there is a risk of them being cracked or bypassed.",complexity:"Advanced",influence:"May cause security processes within the application to be broken and data to be forged.",references:[{title:"What Is Reverse Engineering?"}],keywords:["Application Reverse Engineering","app reversing","APK decompilation","source code recovery","binary analysis","reverse app logic"]},Vi={R0051:Ni,"R0051-001":{title:"Application Traffic Interception",definition:"Restoring an application's request structure and monitoring response data through packet capture.",description:"Packet capture involves intercepting, replaying, editing, and saving data packets sent and received over the network. Through packet capture, an application's request methods and structure can be analyzed to enable business logic reconstruction, simulation, and process automation as a substitute for the client (R0001).",complexity:"Advanced",influence:"May cause security processes within the application to be broken and data to be forged.",references:[{title:"MASTG-TEST-0244: Missing Certificate Pinning in Network Traffic - OWASP",link:"https://mas.owasp.org/MASTG/tests/android/MASVS-NETWORK/MASTG-TEST-0244/"}],keywords:["Application Traffic Interception","packet capture","MITM proxy","request replay","traffic sniffing","API interception"]},"R0051-002":{title:"HTTP Request Analysis",definition:"Restoring an application's request structure and monitoring response data through packet capture.",description:"For applications that transmit data using text-based protocols such as HTTP/HTTPS, a man-in-the-middle can be used to capture sent and received data, thereby reconstructing the application's execution logic to enable automated operations.",complexity:"Intermediate",influence:"May cause security processes within the application to be broken and data to be forged.",references:[{title:"Complete HTTP Request Analysis"}],keywords:["HTTP Request Analysis","HTTP packet capture","HTTPS interception","request inspection","API request analysis","man-in-the-middle proxy"]}},Ki=e({R0052:()=>Qi,default:()=>_i}),Qi={title:"Low Price, High Shipping",definition:"A seller lists products at a relatively low price but compensates for the cost gap by inflating shipping fees.",description:"This strategy may make products appear competitively priced to attract shoppers, but the seller actually earns more profit through excessive shipping charges.",complexity:"Basic",influence:"Shoppers may purchase items without noticing the high shipping fees, leading to a poor experience; for the platform, inflated shipping fees from sellers may damage the platform's reputation.",references:[{title:"Gaoyou Court Press Conference on Combating Telecom and Cyber Fraud"}],keywords:["Low Price, High Shipping","shipping fee scam","inflated shipping charges","price plus shipping manipulation","postage padding","hidden shipping markup"]},_i={R0052:Qi},Yi=e({R0053:()=>Ji,default:()=>Xi}),Ji={title:"Malicious User Harassment",definition:"A seller uses improper means to continuously and intentionally harass users.",description:"May include but is not limited to frequent solicitation, false advertising, threats, intimidation, and persistent harassing messages. More severe cases include mailing razor blades or cash-on-delivery packages to users. Many cases arise from transaction disputes, such as coercing users to retract negative reviews or retaliating against users who file complaints.",complexity:"Basic",influence:"May cause distress and a poor experience for users.",references:[{title:"How Does Taobao Determine Buyer Harassment? What Are the Penalties?"}],keywords:["Malicious User Harassment","buyer harassment","seller harassment","threatening messages","targeted harassment","abusive contact"]},Xi={R0053:Ji},Zi=e({R0054:()=>$i,default:()=>et}),$i={title:"Malicious Returns",definition:"A buyer returns goods not for legitimate reasons, but to disrupt the seller or platform, or to gain improper benefits.",description:"A buyer purchases high-value, large, or scarce items with the intent to disrupt or damage, then initiates a return as soon as the goods arrive or before they arrive, causing financial loss or reputational damage to the seller through high return rates. Alternatively, a buyer uses the 7-day no-questions-asked return policy on high-value items after using them, causing depreciation, then colluding with insiders to purchase the depreciated item.",complexity:"Basic",influence:"Consumes the seller's profits, inventory, reputation, or supply chain costs.",references:[{title:"Buyer Uses Courier Tracking Number for Malicious Refund of Nearly 40,000 Yuan, Faces Fraud Charges"}],keywords:["Malicious Returns","return abuse","refund abuse","serial returns abuse","friendly fraud returns","return policy abuse"]},et={R0054:$i,"R0054-001":{title:"Bulk Refunds",definition:"Placing bulk orders through the same or different accounts and initiating illegitimate bulk returns or refunds.",description:"Using automated or manual means to place large numbers of orders or high-value orders, then bulk-canceling and requesting refunds, maliciously consuming supply chain costs or causing the seller's return rate to rise.",complexity:"Intermediate",influence:"Disrupts the seller's normal operations, causing supply chain losses or a drop in ratings and rankings.",references:[{title:"Tai'an Announces Typical Cases of Combating New Telecom and Cyber Crimes"}],keywords:["Bulk Refunds","mass refunds","bulk cancellation fraud","refund bombing","order cancellation abuse","refund abuse at scale"]},"R0054-002":{title:"Return Fraud",definition:"A buyer returns a counterfeit, used, empty, incomplete, or substitute item instead of the original purchased product.",description:"The returned item is not the actual item that was shipped — such as returning a counterfeit or a different product (buy A, return B). The quantity of returned items differs from what was actually shipped, including empty packages.",complexity:"Basic",influence:"Causes financial loss to the platform or seller.",references:[{title:"January Digital Retail: Taobao Flash Sale Challenges Instant Retail Dominance, Three Sheep Resumes Streaming"}],keywords:["Return Fraud","refund fraud","wardrobing","returning counterfeit item","buy and return switch","empty box return"]},"R0054-003":{title:"Flash Return Arbitrage",definition:"Placing an order to receive gifts, vouchers, or discounts, then immediately canceling the order to extract the benefits.",description:"A targeted fraudster may stockpile large numbers of accounts and monitor platform or merchant promotions in real time. Upon finding a profitable opportunity, they place bulk orders via automation, extract coupons, gifts, or other benefits, and then immediately cancel the orders for profit.",complexity:"Intermediate",influence:"Causes financial loss to the platform and sellers.",references:[{title:"Exploiting Platform Flash Refund Rules: Order Brushing and Faking Returns Constitutes Fraud"}],keywords:["Flash Return Arbitrage","buy-cancel arbitrage","promo abuse refund","gift with purchase abuse","voucher extraction","instant refund arbitrage"]},"R0054-004":{title:"Malicious Refusal of Delivery",definition:"A buyer refuses to accept goods for retaliatory or disruptive purposes, occupying or consuming the seller's supply chain resources and causing financial loss.",description:"A typical malicious attack scenario: a buyer purchases large items such as appliances, electronics, construction materials, or tires, then goes unreachable or refuses delivery when the courier arrives, occupying and consuming the seller's supply chain costs.",complexity:"Basic",influence:"Causes supply chain losses to the seller.",references:[{title:"Ministry of Public Security Announces Top 10 Financial Black-Grey Market Crime Cases"}],keywords:["Malicious Refusal of Delivery","delivery refusal abuse","reject-on-delivery abuse","failed delivery sabotage","malicious non-acceptance"]}},it=e({R0055:()=>tt,default:()=>at}),tt={title:"Unauthorized Discount Purchase",definition:"Zero-price or below-cost purchases resulting from business logic errors or misconfigured prices and coupons.",description:"This attack may be discovered accidentally, but is more likely the result of an attacker probing at scale through automated bulk cart additions, modifying submitted amounts or quantities, or collecting and stacking coupons. After discovering a vulnerability, attackers typically exploit it while simultaneously publicizing it to achieve safety in numbers and conceal their identity, causing greater losses to the platform or merchant.",complexity:"Basic",influence:"Causes significant financial losses to the platform and merchants.",references:[{title:"Financial Weekly: Over 4 Million Financial Black-Grey Market Practitioners in China"}],keywords:["Unauthorized Discount Purchase","price glitch abuse","zero dollar order","below-cost purchase fraud","coupon stacking abuse","underpriced order exploit"]},at={R0055:tt,"R0055-001":{title:"Coupon Restriction Bypass",definition:"Restricted coupons are claimed or used outside of their intended restrictions.",description:"Two scenarios: first, non-public coupons, coupons claimable under specific conditions, or coupons issued to specific groups are claimed without meeting the restrictions; second, coupons restricted to specific usage scenarios or conditions are used outside those restrictions. Restrictions include: specific time windows, specific user groups, specific product pairings, specific price thresholds, coupon stacking limits, and more.",complexity:"Basic",influence:"Exploits platform marketing activity benefits, causing financial losses to the platform.",references:[{title:"OWASP Automated Threat: OAT002 Token Cracking"}],keywords:["Coupon Restriction Bypass","coupon abuse","promo code abuse","coupon eligibility bypass","voucher restriction bypass","coupon stacking bypass"]}},nt=e({R0056:()=>ot,default:()=>st}),ot={title:"Fake Reviews",definition:"A seller purchases fake positive reviews to boost product reputation or search ranking weight.",description:"Sellers collude with buyers through low-price orders, empty package shipments, or virtual deliveries to generate fake transactions and bulk positive reviews, boosting store credibility or product rankings.",complexity:"Basic",influence:"Undermines platform fairness and distorts ranking algorithms.",references:[{title:"Ji'an Dismantles Order Brushing and Fake Review Black Industry Chain"}],keywords:["Fake Reviews","review fraud","shill reviews","paid reviews","review manipulation","astroturfing"]},st={R0056:ot},rt=e({R0057:()=>ct,default:()=>lt}),ct={title:"Category / Brand Miscategorization",definition:"A seller deliberately lists products under incorrect categories or brands to gain more exposure and attract buyers.",description:"This behavior may involve false advertising, misleading consumers, and disrupting market order, violating platform rules and business ethics. Miscategorized products may mislead consumers during search and browsing, showing them products that do not match their actual needs. It can cause category confusion, making product displays and search results on the platform disorganized and unclear. By deliberately placing products in inappropriate categories, sellers may attempt to gain an unfair competitive advantage and make their products more prominent in search results.",complexity:"Basic",influence:"The platform may face criticism from consumers and other merchants due to miscategorized products, damaging the platform's reputation and credibility.",references:[{title:"Review of 40 Consumer Scandals from 315 Hot Search: Seven Industry Scandals Exposed"}],keywords:["Category / Brand Miscategorization","category spoofing","brand spoofing","misclassified listing","wrong category listing","brand mislabeling"]},lt={R0057:ct},dt=e({R0058:()=>ut,default:()=>pt}),ut={title:"Price Fraud",definition:"An operator uses false or misleading pricing forms or price tactics to deceive or induce consumers or other operators into transactions.",description:"The following pricing behaviors or price tactics are recognized as price fraud: 1. False pricing. 2. Dual pricing. 3. Deceptive pricing. 4. Vague or exaggerated pricing. 5. False discounts. 6. Failure to mark prices on clearance items. 7. Failure to truthfully disclose gift conditions. 8. Hidden price conditions. 9. Fabricated original prices. 10. Failure to honor price commitments. 11. Fabricated comparison prices. 12. Price-quality mismatch. 13. False claims of 'government-set prices'.",complexity:"Basic",influence:"Creates significant compliance risks for the platform and increases the volume of customer complaints.",references:[{title:"CCTV Cracks Down on Medical Aesthetics Black Market in 2025: Will Channel Chaos End in 2026?"}],keywords:["Price Fraud","deceptive pricing","bait pricing","false discounts","dual pricing","price deception"]},pt={R0058:ut},mt=e({R0059:()=>gt,default:()=>ft}),gt={title:"Trade Secret Leakage",definition:"An employee discloses a company's trade secrets or sensitive information to third parties without authorization, or uses such information for personal or others' gain.",description:"Scenarios include but are not limited to: departing employees taking sensitive information for competitive use, competitors stealing business or research results, internal employees leaking secrets out of dissatisfaction or greed, external attackers obtaining credentials through social engineering or cyberattacks to steal information, and employees inadvertently leaking sensitive data when using unauthorized cloud services or storage devices.",complexity:"Basic",influence:"May cause serious financial losses, reputational damage, and legal liability for the company.",references:[{title:"Anti-Unfair Competition Law of the PRC - National Laws and Regulations Database"}],keywords:["Trade Secret Leakage","confidential information leak","business secret leak","IP theft","proprietary information disclosure","insider leak"]},ft={R0059:gt},ht=e({R0060:()=>yt,default:()=>bt}),yt={title:"Money Laundering Risk",definition:"Using legitimate trading platforms to conduct illegal transactions in order to transfer money.",description:"Many gambling websites establish storefronts on legitimate trading platforms and use virtual goods delivery or empty package shipments to process deposits for gamblers. Pornographic scam websites redirect visitors attempting to purchase premium services to legitimate trading platforms to order virtual goods such as phone cards, fuel cards, or VIP vouchers, but never provide the premium services, causing a sharp increase in customer complaints against the legitimate platform.",complexity:"Advanced",influence:"Creates significant compliance risks for the platform and increases the volume of customer complaints.",references:[{title:"Further Crackdown on Financial Black-Grey Market: Industry Faces Comprehensive Rectification"}],keywords:["Money Laundering Risk","transaction laundering","trade-based money laundering","TBML","merchant laundering","washing illicit funds"]},bt={R0060:yt},kt=e({R0061:()=>vt,default:()=>wt}),vt={title:"Recycled Phone Number Takeover",definition:"A new phone number holder gains access to the previous holder's account through password recovery or SMS verification code login mechanisms.",description:"A typical malicious attacker can collude with insiders at telecom operators to obtain expired phone numbers in bulk, enabling large-scale account takeovers. Major domestic telecom operators now provide phone number verification APIs that can determine whether a number has been reassigned or expired, allowing platforms to check phone number status accordingly.",complexity:"Basic",influence:"Leads to platform user accounts being impersonated.",references:[{title:"Cyber Black-Grey Market Approaches 100 Billion Yuan: Personal Information Leakage Is the Root Cause"}],keywords:["Recycled Phone Number Takeover","reassigned number takeover","phone number recycling attack","SMS login takeover","number reassignment hijack","ATO via recycled number"]},wt={R0061:vt},Rt=e({R0062:()=>At,default:()=>xt}),At={title:"Illegal Cash-Out",definition:"Converting funds into a more convenient or valuable form through fraudulent transactions, using the extracted funds for illegal or prohibited purposes.",description:"Refers to converting one form of funds into another more usable or valuable form. This typically involves converting non-cash assets such as credit card limits, points, coupons, or virtual currencies into cash. For example, some people may use a credit card to purchase returnable goods and then return them for cash. Others may sell virtual currencies on trading platforms to convert them into cash.",complexity:"Intermediate",influence:"Causes financial losses and compliance risks for the platform.",references:[{title:"Tighter Credit Card Fund Controls: Further Crackdown on Illegal Cash-Out"}],keywords:["Illegal Cash-Out","fraudulent cash-out","cash-out fraud","illicit fund extraction","balance laundering","arbitrage cashout"]},xt={R0062:At,"R0062-001":{title:"Credit Card / Loan Cash-Out",definition:"Exploiting platform mechanisms to cash out credit card limits or shopping loans.",description:"Exploiting platform business process vulnerabilities to withdraw shopping loans to a bank card, or colluding between buyers and sellers to fake shipments and extract shopping loan funds.",complexity:"Intermediate",influence:"Causes financial losses and compliance risks for the platform.",references:[{title:"Stronger Supervision on Credit Card Fund Use and Cash-Out Violations",link:"https://3g.china.com/bank/13003064/20220805/37279656.html"}],keywords:["Credit Card / Loan Cash-Out","credit limit cash-out","shopping loan cash-out","loan arbitrage","synthetic purchase cash-out","fake merchant cash-out"]},"R0062-002":{title:"Illegal Points Cash-Out",definition:"Obtaining points through illegal means or converting points into cash in violation of terms of service.",description:"Illegal points cash-out may include: a) Fabricated transactions: creating fake transactions to earn points, such as using one's own credit card at one's own store, then canceling the transactions while retaining the points. b) Exploiting system vulnerabilities: using loopholes to obtain extra points without actual spending. c) Buying and selling points: purchasing others' points and reselling them at a higher price, or selling goods redeemed with points at full market price.",complexity:"Intermediate",influence:"Causes financial losses and compliance risks for the platform.",references:[{title:"Case Study: Operating a Money Laundering Platform for Cyber Black-Grey Market Merchants"}],keywords:["Illegal Points Cash-Out","points cashout","loyalty points laundering","reward points arbitrage","points monetization abuse","points resale fraud"]}},Ct=e({R0063:()=>St,default:()=>It}),St={title:"Duplicate Product Listings",definition:"A seller excessively lists the same or similar products in their store, resulting in duplicate product listings and redundant inventory.",description:"Duplicate listings generally include: products with highly similar titles, images, key attributes, or descriptions. Listing the same product separately by different colors, sizes, bundles, or specifications is generally considered duplicate listing.",complexity:"Basic",influence:"Degrades the shopping experience and may cause transaction loss; occupies platform search and recommendation resources, damaging the platform's reputation.",references:[{title:"What Is Duplicate Product Listing?"}],keywords:["Duplicate Product Listings","duplicate listings","listing spam","duplicate SKU listings","repeat listings","catalog spam"]},It={R0063:St},Tt=e({R0064:()=>Pt,default:()=>Mt}),Pt={title:"Order-Splitting Arbitrage",definition:"Exploiting shipping thresholds, price differences, or bundled gift items by placing abnormal combined orders and then canceling part of the order to extract benefits.",description:"Many trading platforms offer free shipping above a certain amount, tiered discounts, gifts, or rebates. Attackers first build up an order to meet the benefit threshold, then return some or all of the items to extract the benefit.",complexity:"Basic",influence:"Extracts platform or merchant discounts and rebates.",references:[{title:"Black Market Big Data: 2025 Global E-Commerce Fraud Risk Research Report"},{title:"Buyer Maliciously Pads Order Then Requests Refund — What Should Merchants Do?"}],keywords:["Order-Splitting Arbitrage","split order abuse","partial cancellation arbitrage","free shipping abuse","gift threshold abuse","cart splitting exploit"]},Mt={R0064:Pt},Bt=e({R0065:()=>Ft,default:()=>Ot}),Ft={title:"Employee Error Risk",definition:"Potential security risks arising from employee negligence, improper operations, or lack of security awareness when handling information, using technical tools, or performing tasks, which may lead to accidental disclosure of sensitive information.",description:"Common risk scenarios caused by employee negligence or improper operations include: password leakage (employees saving passwords in insecure locations, using weak passwords, or sharing passwords, leading to account compromise); malware infection (clicking malicious links, downloading suspicious attachments, or visiting unsafe websites); data loss from misoperations (accidentally deleting, modifying, or mishandling sensitive data); unauthorized data access (employees inadvertently accessing sensitive information outside their work scope); and device loss or theft (lost or stolen mobile devices such as laptops or phones leading to sensitive information exposure).",complexity:"Basic",influence:"These risks may include data breaches, system failures, network intrusions, and other security vulnerabilities, causing potential financial losses and reputational damage to the organization.",references:[{title:"Insider Threat Mitigation Guide - CISA",link:"https://www.cisa.gov/resources-tools/resources/insider-threat-mitigation-guide"}],keywords:["Employee Error Risk","human error risk","employee negligence","accidental data exposure","operational mistake","misconfiguration by staff"]},Ot={R0065:Ft},Dt=e({R0066:()=>zt,default:()=>qt}),zt={title:"In-Platform Message Harassment",definition:"Using the platform's messaging mechanism to send harassing messages to others.",description:"Unlike text content risks, message harassment is carefully crafted to evade keyword blacklists and may not trigger the platform's keyword alerts. Message harassment is a widespread risk. Some platforms allow users to configure which groups of people can send them messages, which is an effective defensive strategy.",complexity:"Basic",influence:"Causes significant disruption to platform customer service or merchants; in severe cases may lead to user churn or physical harm.",references:[{title:"Protecting Personal Information: Internet Platforms Pilot 'Privacy Numbers' in Advertising"}],keywords:["In-Platform Message Harassment","in-app message harassment","DM harassment","private message abuse","message spam abuse","offensive direct messages"]},qt={R0066:zt},Ut=e({R0067:()=>Wt,default:()=>Lt}),Wt={title:"File or Document Theft",definition:"The potential threat of unauthorized individuals or organizations obtaining, copying, distributing, or using confidential files or documents, which may include business plans, customer data, contracts, financial reports, intellectual property, and other sensitive information.",description:"Possible file or document theft scenarios include: cyberattacks (hackers obtaining sensitive files through phishing, malware, or ransomware); insider leaks (employees, partners, or vendors abusing access privileges to steal confidential files for personal or competitor benefit); physical intrusion (intruders gaining access to paper or electronic sensitive files by breaking into offices or through lost/stolen devices); and social engineering (attackers gaining access to sensitive files through deception, impersonation, or trust manipulation).",complexity:"Basic",influence:"Harms manifest across multiple dimensions: intellectual property loss threatening the company's innovation capacity; competitors gaining business strategies and plans damaging competitive position; files containing customer information causing trust issues and legal liability; and violations of data protection regulations leading to compliance issues, lawsuits, and fines.",references:[{title:"Data from Information Repositories (T1213) - MITRE ATT&CK"}],keywords:["File or Document Theft","document exfiltration","file exfiltration","confidential document leak","sensitive file theft","insider document theft"]},Lt={R0067:Wt},Et=e({R0068:()=>Gt,default:()=>Ht}),Gt={title:"After-Sales Rights Abuse",definition:"Malicious exploitation and excessive use of rights granted by the platform.",description:"For example, national regulations require online shopping platforms to offer 7-day no-questions-asked returns. Buyers exploit this mechanism to use products or services for free and then initiate a return within 7 days.",complexity:"Basic",influence:"Causes financial losses to the platform or sellers.",references:[{title:"Generali China Life Beijing 315 Risk Alert: Resist Black-Grey Market, Protect Information Security"}],keywords:["After-Sales Rights Abuse","after-sales abuse","consumer rights abuse","return policy exploitation","warranty abuse","7-day return abuse"]},Ht={R0068:Gt,"R0068-001":{title:"Malicious Complaints",definition:"Filing malicious complaints against a trading platform or against merchants on a trading platform.",description:"With the goal of gaining improper benefits or forcing the target to be penalized, attackers file malicious complaints against a trading platform through regulatory bodies, or against merchants through the trading platform.",complexity:"Basic",influence:"Causes financial or reputational losses to the platform or sellers.",references:[{title:"Black-Grey Market Preying on Consumer Rights Advocates"}],keywords:["Malicious Complaints","bad-faith complaints","vexatious complaints","complaint abuse","reporting abuse","malicious reporting"]},"R0068-002":{title:"Malicious Claims",definition:"Bulk-purchasing expired, unlisted, or counterfeit goods and filing tenfold compensation claims.",description:"Using bulk searches, data scraping, and similar methods to find expired, counterfeit, substandard, or non-compliant products (e.g., containing advertising law prohibited terms). After placing orders, the buyer complains about the seller's violations and demands large sums of money in exchange for withdrawing the complaint.",complexity:"Intermediate",influence:"Causes financial losses to the platform or sellers.",references:[{title:"Meituan Reports Jan-Aug Black-Grey Market Crackdown Results: Over 50 Million Yuan Involved"}],keywords:["Malicious Claims","compensation claim abuse","bad-faith claims","tenfold compensation claims","counterfeit claim arbitrage","professional claimants"]}},jt=e({R0069:()=>Nt,default:()=>Vt}),Nt={title:"Upload Abuse",definition:"Using a business system's normal file upload functionality to upload unexpected files.",description:"Business systems with user-generated content features such as image or file uploads can be exploited by attackers who upload files through the upload interface that are not intended for the platform's normal use, but rather for illegal storage, distribution of illegal content, and other purposes.",complexity:"Basic",influence:"Consumes platform storage and network resources, and may create compliance risks.",references:[{title:"Jiang Ning Appointed as Xiaoma Consumer Finance GM, Stepping Up Human-AI Collaborative Digital Strategy"}],keywords:["Upload Abuse","file upload abuse","malicious upload","unexpected file upload","storage abuse","illegal content upload"]},Vt={R0069:Nt,"R0069-001":{title:"Image Hosting Abuse",definition:"Users upload images or files through the platform's normal image upload feature that are not intended for the site's normal functions, and abuse the resources for external access.",description:"Two common scenarios: first, users upload large volumes of images to use the platform's image upload feature as personal cloud storage; second, users upload video files disguised as images. Users slice video files into segments, append each segment to an image file to disguise them as images, upload the sliced files via the image upload interface, and use an m3u file to aggregate the image URLs for video playback. This is common in features that allow immediate image upload and return a URL, such as ID photo upload before identity verification or avatar upload after account creation. If the page is not finally submitted, it typically bypasses backend review, creating a blind spot that can be exploited to distribute pirated or pornographic videos.",complexity:"Basic",influence:"Disrupts normal system operations, consumes large amounts of network bandwidth and storage space, and creates compliance risks.",references:[{title:"Remote Image Hosting Service Gradually Shutting Down"}],keywords:["Image Hosting Abuse","free image hosting abuse","external image hosting","hotlink image hosting","personal cloud storage abuse","CDN abuse"]},"R0069-002":{title:"Cloud Storage Abuse",definition:"Similar to image hosting abuse (R0069-001), but the difference is that cloud storage is a feature of the business's cloud service rather than an ancillary resource for user-generated content.",description:"Using the cloud storage feature provided by the business to upload unexpected or illegal content. Cloud storage may be part of a cloud computing service or a cloud drive, and is typically subject to weaker content moderation than user-generated content, making it potentially exploitable by bad actors to distribute pirated or pornographic videos.",complexity:"Basic",influence:"Disrupts normal system operations, consumes large amounts of network bandwidth and storage space, and creates compliance risks.",references:[{title:"Alibaba OSS Storage Bucket Breached, Malicious Shell Scripts Distributed via Steganography"}],keywords:["Cloud Storage Abuse","cloud drive abuse","object storage abuse","illegal file hosting","storage bucket abuse","pirated content hosting"]}},Kt=e({R0070:()=>Qt,default:()=>_t}),Qt={title:"Automated Reselling",definition:"Using automated means to automatically purchase and resell goods through a platform's normal transaction process.",description:"Automated reselling typically serves three purposes: first, buying low and selling high to profit from price differences; second, listing products without actual stock and fulfilling orders through other stocked stores; third, using automation to bulk-create store clusters for mass product listing.",complexity:"Intermediate",influence:"Buy-low-sell-high behavior, once discovered by users, creates the impression of inflated prices on the platform, causing reputational damage and user churn; dropshipping stores often negate competitive advantages or lead to unfair competition; store clusters occupy large amounts of search and recommendation resources, leading to unfair competition.",references:[{title:"OAT-005 Scalping - OWASP"}],keywords:["Automated Reselling","scalper bots","reseller bots","automated purchasing","bot resale","auto-buy reselling"]},_t={R0070:Qt,"R0070-001":{title:"Buy Low, Sell High",definition:"Selling products from other platforms or stores at a higher price on the current platform or store to profit from the price difference.",description:"A typical buy-low-sell-high approach involves significantly marking up a product's price and then using search bidding ranking mechanisms to place the product at the top of results for greater exposure.",complexity:"Intermediate",influence:"This behavior creates the impression of inflated prices on the platform for users, leading to user churn.",references:[{title:"OAT-005 Scalping - OWASP"}],keywords:["Buy Low, Sell High","retail arbitrage","price arbitrage","cross-platform arbitrage","markup reselling","product flipping"]},"R0070-002":{title:"Dropshipping Store",definition:"Listing products from other platforms or stores on the current platform or store, and placing orders through the original stocked store when a user places an order.",description:"Buy-low-sell-high (R0070-001) is generally also a form of dropshipping, but buy-low-sell-high is more focused on gaining exposure, while dropshipping is more focused on gaining order volume. For example, if a seller only has a store on Platform A and not on Platform B, Platform A gains a competitive advantage. But if the seller lists products on Platform B and fulfills orders through Platform A when users order on B, this competitive advantage is negated — especially if Platform B subsidizes the originally unstocked products, creating the illusion that Platform B is always cheaper than Platform A.",complexity:"Intermediate",influence:"Cross-platform dropshipping reduces the competitive advantage of the original platform and may lead to unfair competition, causing financial or reputational losses.",references:[{title:"Drop shipping - Wikipedia"}],keywords:["Dropshipping Store","dropshipping","no-inventory store","order forwarding store","middleman store","one-click fulfillment"]},"R0070-003":{title:"Store Cluster",definition:"May be a form of dropshipping store (R0070-002) or may have actual stock. Typically refers to bulk-creating stores to increase exposure.",description:"By bulk-creating large numbers of stores to increase exposure and expand the display area of products or services, attracting more potential customers. This practice is typically aimed at increasing product or service visibility on the platform, improving exposure in search results, and gaining more traffic and sales opportunities.",complexity:"Intermediate",influence:"Occupies display opportunities of other stores on the platform, and the mass listing of similar products makes it harder for users to discover differentiated products.",references:[{title:"OAT-005 Scalping - OWASP"}],keywords:["Store Cluster","store farming","multi-store operation","store matrix","store network","bulk-created stores"]}},Yt=e({R0071:()=>Jt,default:()=>Xt}),Jt={title:"Generative AI Risk",definition:"Risks and hazards introduced by AIGC (Artificial Intelligence Generated Content) generative AI.",description:"AI-generated content risks fall into several categories: sensitive information being embedded in generated content causing data leakage; generated content containing illegal, non-compliant, or unethical material; and the risk of platform content quality degradation from bulk, cheap, and low-quality AI-generated content.",complexity:"Basic",influence:"AI-generated content risks may create compliance risks for the platform and increase the volume of customer complaints.",references:[{title:"Interim Measures for the Management of Generative Artificial Intelligence Services - Gov.cn"},{title:"Measures for the Labeling of AI-Generated Synthetic Content - Gov.cn"}],keywords:["Generative AI Risk","AIGC risk","genAI risk","LLM risk","AI content risk","model governance risk"]},Xt={R0071:Jt,"R0071-001":{title:"AIGC Privacy Leakage",definition:"AIGC leaking sensitive information learned during large model training into generated content.",description:"Sensitive information leakage may occur in several ways: (1) Training data leakage: if text data containing sensitive information was used to train the large language model, the model may generate similar sensitive information based on that data. (2) Model memorization: large language models may sometimes exhibit memorization, including previously input information in generated text. If a user provides sensitive information during a conversation, the model may include it in subsequent generations. (3) Context sensitivity: the model may base generated text on prior context, which may include sensitive information provided by the user, and may implicitly include related information in subsequent generations even if the user no longer explicitly mentions it.",complexity:"Intermediate",influence:"AIGC sensitive information leakage may create compliance risks for the platform.",references:[{title:"Illegal Proxy Rights Defense Surges 42%: How Technology Can Break Through Financial Black-Grey Market Governance"}],keywords:["AIGC Privacy Leakage","training data leakage","model data leakage","memorization leak","PII leakage from model","sensitive output leakage"]},"R0071-002":{title:"AIGC Compliance Risk",definition:"AI-generated content may contain illegal, non-compliant, or unethical material.",description:"Large language model content compliance risks mainly include: misleading information, discriminatory content, privacy violations, malicious misuse, intellectual property issues, regulatory compliance issues, and lack of transparency. These risks may lead to the spread of false information, discriminatory speech, privacy violations, malicious misuse, and regulatory non-compliance.",complexity:"Basic",influence:"AIGC compliance risks may create compliance risks for the platform and increase the volume of customer complaints.",references:[{title:"Interim Measures for the Management of Generative Artificial Intelligence Services - Gov.cn"},{title:"Legal Compliance Risks and Prevention in the AIGC Wave"}],keywords:["AIGC Compliance Risk","AI compliance risk","unsafe model output","policy-violating AI content","illegal generated content","responsible AI risk"]},"R0071-003":{title:"AI-Generated Low-Quality Content",definition:"Bulk, cheap, and low-quality large language model generated content may introduce various risks of platform content quality degradation.",description:"First, due to the lack of effective content filtering mechanisms, large volumes of spam, fake news, and low-quality reviews may emerge, degrading overall platform content quality. Second, generated content may involve privacy violations, malicious attacks, and inappropriate speech, exacerbating the spread of misinformation and social tension on social platforms. Additionally, large-scale use of language models to generate content may encourage bot-like behavior, making it difficult for real users to distinguish fake accounts and artificially generated content, damaging the platform's credibility and user experience.",complexity:"Intermediate",influence:"Leads to degraded platform content quality and undermines the motivation of original and high-quality content creators.",references:[{title:"Measures for the Labeling of AI-Generated Synthetic Content - Gov.cn"}],keywords:["AI-Generated Low-Quality Content","AI spam","content farm AI","low-effort AI content","synthetic content pollution","LLM spam"]},"R0071-004":{title:"AI Hallucination Risk",definition:"Large language models generating seemingly plausible but actually incorrect or fabricated information — known as 'hallucinations' — which may mislead user decisions.",description:"AI hallucination refers to large language models generating content that is factually incorrect, logically inconsistent, or entirely fabricated, yet expressed with apparent confidence and plausibility. Key risk scenarios include: (1) Fabricated facts: the model invents non-existent events, people, data, or citations. (2) Incorrect professional advice: generating erroneous advice in medical, legal, financial, and other professional domains, potentially causing serious consequences. (3) False citations: generating seemingly real but non-existent academic papers, legal provisions, or news reports. (4) Logical reasoning errors: producing seemingly valid but actually incorrect reasoning chains in complex inference tasks.",complexity:"Intermediate",influence:"Users are misled into making wrong decisions; incorrect advice in professional domains may cause serious consequences; platform credibility declines.",references:[{title:"Survey on Hallucination Problems in Large Language Models"}],keywords:["AI Hallucination Risk","LLM hallucination","fabricated AI output","AI confabulation","false AI answers","model hallucinations"]},"R0071-005":{title:"AI Model Poisoning Risk",definition:"The risk that attackers contaminate training data or model parameters to cause the AI model to exhibit preset erroneous behaviors or backdoors.",description:"AI model poisoning refers to attackers injecting malicious data or modifying model parameters during the training or fine-tuning phase, causing the model to produce attacker-intended erroneous outputs under specific trigger conditions. Main attack methods include: (1) Data poisoning: injecting carefully crafted malicious samples into training data to cause the model to learn incorrect patterns. (2) Backdoor attacks: planting a backdoor in the model so that when input contains a specific trigger, the model outputs attacker-controlled results. (3) Model tampering: modifying model weights during distribution to implant malicious behavior. (4) Federated learning poisoning: in federated learning scenarios, malicious participants submit poisoned model updates.",complexity:"Advanced",influence:"AI system decisions are manipulated, security detection is bypassed, and model trustworthiness is lost.",references:[{title:"Survey on AI Model Security and Poisoning Attacks"}],keywords:["AI Model Poisoning Risk","training data poisoning","model backdoor","poisoned model","malicious fine-tuning","data poisoning attack"]}},Zt=e({R0072:()=>$t,default:()=>ea}),$t={title:"Employee Corruption",definition:"Employee corruption refers to employees using improper means to seek personal gain, abuse their authority, accept bribes, or engage in corrupt activities in the workplace.",description:"This may include falsifying expense reports, soliciting kickbacks from suppliers, misusing company resources, bribery, or participating in other corrupt activities.",complexity:"Basic",influence:"Employee corruption harms include damaging the company's reputation, undermining internal trust, reducing work efficiency, causing resource waste, increasing compliance risks, and ultimately potentially triggering legal liability and financial losses.",references:[{title:"Corporate fraud - Wikipedia"}],keywords:["Employee Corruption","internal corruption","workplace bribery","kickback scheme","abuse of authority","employee bribery"]},ea={R0072:$t,"R0072-001":{title:"Insider-Outsider Collusion",definition:"Internal employees collude with external individuals or organizations to commit fraud, embezzlement, bribery, or other improper acts that violate the company's interests and regulations.",description:"Behaviors or scenarios include employees colluding with suppliers to falsify expenses, corrupt transactions, and insider-outsider collusion for fraudulent activities.",complexity:"Basic",influence:"May cause financial losses and reputational damage to the company, while increasing compliance risks and posing a serious threat to the company's sound operations.",references:[{title:"Insider threat - Wikipedia"}],keywords:["Insider-Outsider Collusion","insider collusion","external collusion","inside job","employee-supplier collusion","insider fraud ring"]}},ia=e({R0073:()=>ta,default:()=>aa}),ta={title:"Device Loss",definition:"An employee's work device (such as a laptop, tablet, or phone) is lost or stolen in the workplace or elsewhere.",description:"Device loss scenarios are varied, including on public transportation, at airports, hotels, coffee shops, at home, gyms, and other environments. This risk may occur due to employee negligence, haste, or theft, exposing the organization to risks of data leakage, security vulnerabilities, and business disruption.",complexity:"Basic",influence:"May lead to potential information leakage, security vulnerabilities, and business risks.",references:[{title:"Data breach - Wikipedia"}],keywords:["Device Loss","lost laptop","stolen work phone","lost corporate device","device theft","endpoint loss"]},aa={R0073:ta},na=e({R0074:()=>oa,default:()=>sa}),oa={title:"Privacy Compliance Risk",definition:"Privacy compliance risk refers to the risk that an organization fails to comply with relevant privacy regulations or policies when processing personal data, potentially violating individuals' privacy rights and triggering legal liability and negative consequences.",description:"Possible privacy compliance risk scenarios include: unauthorized data collection (collecting personal data without explicit user consent); non-transparent data processing (failing to inform users of the purpose, methods, and use of data collection); data breaches (personal data leakage due to security vulnerabilities, internal errors, or external attacks); violation of data retention periods; failure to provide access and modification rights; lack of data security measures such as encryption and access controls; violation of cross-border data transfer regulations; and failure to fulfill data processing agreements.",complexity:"Basic",influence:"May lead to lawsuits, fines, reputational damage, and loss of customer trust.",references:[{title:"Personal Information Protection Law of the PRC"},{title:"Measures for Compliance Auditing of Personal Information Protection"},{title:"Regulation on the Security and Management of Network Data"}],keywords:["Privacy Compliance Risk","data privacy compliance","personal data compliance","privacy law risk","consent compliance","data protection compliance"]},sa={R0074:oa},ra=e({R0075:()=>ca,default:()=>la}),ca={title:"Critical Information Infrastructure (CII) Compliance Risk",definition:"Compliance risk in the critical information infrastructure domain refers to the risk that an organization fails to meet relevant regulations and address potential threats in the CII sector.",description:"Scenarios include failure to ensure the security of networks and information systems, non-compliance with national and regional information security regulations, and failure to respond to cyberattacks and data breaches.",complexity:"Basic",influence:"May lead to legal sanctions, service disruptions, information leakage, and public safety risks.",references:[{title:"Regulation on the Security and Protection of Critical Information Infrastructure"},{title:"Provisions on the Use and Management of Commercial Cryptography in Critical Information Infrastructure"}],keywords:["Critical Information Infrastructure (CII) Compliance Risk","CII compliance","CIIO compliance","critical infrastructure compliance","critical information infrastructure protection","essential systems compliance"]},la={R0075:ca},da=e({R0076:()=>ua,default:()=>pa}),ua={title:"Classified Protection (MLPS) Compliance Risk",definition:"Multi-Level Protection Scheme (MLPS) compliance risk refers to the potential threat of an organization failing to meet relevant regulations and standards under the information security classified protection system.",description:"Scenarios include failure to meet the security level requirements for information systems under the classified protection system, failure to fulfill information security management responsibilities, and risks of data leakage and unauthorized access.",complexity:"Basic",influence:"Harms may include legal liability, information leakage, service disruptions, and negative impacts on the organization's reputation and trust.",references:[{title:"Network Information Security Classified Protection System - ITSEC"}],keywords:["Classified Protection (MLPS) Compliance Risk","MLPS compliance","Multi-Level Protection Scheme","MLPS 2.0","classified cybersecurity protection","cybersecurity classified protection"]},pa={R0076:ua},ma=e({R0077:()=>ga,default:()=>fa}),ga={title:"Cross-Border Data Transfer Compliance Risk",definition:"Cross-border data transfer compliance risk refers to the potential legal, business, and reputational threats arising from an organization's failure to comply with relevant regulations and requirements during the transnational transmission and processing of data.",description:"Possible scenarios include: unauthorized data transfers (transmitting personal sensitive information to other countries or regions without explicit consent from data subjects, potentially violating data privacy regulations); lack of cross-border data transfer agreements; non-compliance with specific national or regional regulations; and data leakage risk during transmission due to inadequate encryption and security measures.",complexity:"Basic",influence:"Violating cross-border data transfer regulations may result in legal liability, including fines, lawsuits, and other legal sanctions.",references:[{title:"Measures for the Security Assessment of Cross-border Data Transfers - Gov.cn"},{title:"Provisions on Facilitating and Regulating Cross-border Data Flows - Gov.cn"},{title:"Regulation on the Security and Management of Network Data - Gov.cn"}],keywords:["Cross-Border Data Transfer Compliance Risk","data transfer compliance","international data transfer","data localization compliance","cross-border personal data transfer","overseas data transfer risk"]},fa={R0077:ga},ha=e({R0078:()=>ya,default:()=>ba}),ya={title:"Data Breach",definition:"Data breach risk refers to the potential threat of an organization's or individual's sensitive, confidential, or personally identifiable information being disclosed, exposed, or accessed without authorization.",description:"May occur in various scenarios, including cyberattacks, insider leaks, and physical device loss or theft.",complexity:"Basic",influence:"Harms include privacy violations, financial losses, legal liability, and reputational damage, potentially causing serious impacts on both organizations and individuals.",references:[{title:"Data breach - Wikipedia"}],keywords:["Data Breach","data leak","sensitive data exposure","information disclosure","unauthorized data access","PII breach"]},ba={R0078:ya,"R0078-001":{title:"Partner Data Breach",definition:"Sensitive information leakage caused by external entities or service providers that partner with the organization, due to insufficient security measures, technical vulnerabilities, or improper operations when handling, storing, or transmitting data.",description:"Scenarios may include third-party service providers being attacked, unauthorized access, and insecure environments during data transmission.",complexity:"Basic",influence:"Harms include loss of trust from customers and business partners, legal liability, reputational damage, and potential financial losses, posing potential threats to both the organization and its partners.",references:[{title:"Data breach - Wikipedia"}],keywords:["Partner Data Breach","third-party data breach","vendor data breach","supplier breach","service provider breach","partner leak"]}},ka=e({R0079:()=>va,default:()=>wa}),va={title:"Chinese Cryptography Standard (SM) Compliance Risk",definition:"The potential threat of an organization failing to comply with the cryptographic algorithm standards issued by China's State Cryptography Administration (SCA) when using encryption algorithms, which may lead to regulatory non-compliance and technical standard inconsistencies.",description:"Scenarios may involve the inability to meet domestic regulatory requirements due to the use of non-SM algorithms, potential scrutiny from regulatory authorities, and possible challenges regarding technical standard inconsistencies in critical domains.",complexity:"Basic",influence:"Harms include legal liability, compliance issues, and business restrictions in specific domestic markets, potentially damaging the organization's competitiveness and reputation in the Chinese market.",references:[{title:"Cryptography Law of the PRC"},{title:"Regulation on the Administration of Commercial Cryptography"},{title:"Provisions on the Use and Management of Commercial Cryptography in Critical Information Infrastructure"}],keywords:["Chinese Cryptography Standard (SM) Compliance Risk","guomi compliance","SM2 SM3 SM4 compliance","GM/T algorithms","commercial cryptography compliance","State Cryptography Administration standards"]},wa={R0079:va},Ra=e({R0080:()=>Aa,default:()=>xa}),Aa={title:"Device Malware Infection",definition:"Malware or trojans infiltrate an organization's internal network through employee devices or accounts, potentially stealing sensitive information, monitoring operations, or damaging systems.",description:"Scenarios may include employees clicking malicious links, downloading trojan-infected attachments, or being tricked through social engineering, causing malware to enter the internal network.",complexity:"Intermediate",influence:"Harms include sensitive data leakage, network service disruption, damage to information assets, and potential financial losses.",references:[{title:"Malware - Wikipedia"}],keywords:["Device Malware Infection","endpoint malware","trojan infection","workstation compromise","RAT infection","backdoor malware"]},xa={R0080:Aa},Ca=e({R0081:()=>Sa,default:()=>Ia}),Sa={title:"Supply Chain Risk",definition:"Supply chain risk refers to the possibility that products such as software, hardware, and cloud services are exposed to security threats during development, delivery, deployment, and maintenance due to potential threats in supply chain components or links.",description:"Supply chain risk refers to the possibility that products such as software, hardware, and cloud services are exposed to security threats during development, delivery, deployment, and maintenance due to potential threats in supply chain components or links.",complexity:"Intermediate",influence:"Harms include potential business disruption, sensitive information exposure, and system vulnerability exposure, significantly impacting the organization's trust and reliability.",references:[{title:"Supply chain attack - Wikipedia"}],keywords:["Supply Chain Risk","supply chain attack","supply chain compromise","third-party risk","supplier compromise","upstream compromise"]},Ia={R0081:Sa,"R0081-001":{title:"Software Supply Chain Risk",definition:"Software supply chain risk refers to the possibility that software systems are exposed to security threats during development, delivery, deployment, and maintenance due to potential threats in supply chain components or links.",description:"Scenarios include third-party components being attacked, suppliers suffering data breaches, and software development tools being tampered with, potentially leading to malicious code injection, backdoors, or data leakage.",complexity:"Intermediate",influence:"Harms include potential business disruption, sensitive information exposure, and system vulnerability exposure, significantly impacting the organization's trust and reliability.",references:[{title:"Supply chain attack - Wikipedia"}],keywords:["Software Supply Chain Risk","software supply chain attack","dependency confusion","malicious package","CI/CD compromise","package hijacking"]},"R0081-002":{title:"Hardware Supply Chain Risk",definition:"Hardware supply chain risk refers to the possibility that hardware systems are exposed to security threats during development, delivery, deployment, and maintenance due to potential threats in supply chain components or links.",description:"Scenarios include third-party components being attacked, suppliers suffering data breaches, and hardware development tools being tampered with, potentially leading to malicious code injection, backdoors, or data leakage.",complexity:"Intermediate",influence:"Harms include potential business disruption, sensitive information exposure, and system vulnerability exposure, significantly impacting the organization's trust and reliability.",references:[{title:"Supply chain attack - Wikipedia"}],keywords:["Hardware Supply Chain Risk","hardware trojan","firmware tampering","component backdoor","counterfeit hardware","hardware tampering"]},"R0081-003":{title:"Cloud Service Supply Chain Risk",definition:"Cloud service supply chain risk refers to the possibility that cloud services are exposed to security threats during development, delivery, deployment, and maintenance due to potential threats in supply chain components or links.",description:"Scenarios include third-party components being attacked, suppliers suffering data breaches, and cloud service development tools being tampered with, potentially leading to malicious code injection, backdoors, or data leakage.",complexity:"Intermediate",influence:"Harms include potential business disruption, sensitive information exposure, and system vulnerability exposure, significantly impacting the organization's trust and reliability.",references:[{title:"Supply chain attack - Wikipedia"}],keywords:["Cloud Service Supply Chain Risk","cloud provider compromise","SaaS supply chain","managed service compromise","third-party cloud risk","cloud dependency risk"]},"R0081-004":{title:"Outsourced Personnel Risk",definition:"Outsourced personnel risk refers to the possibility that software systems are exposed to security threats due to potential threats from the behavior of outsourced personnel involved in software development, delivery, deployment, and maintenance.",description:"Scenarios include outsourced personnel's accounts being compromised, maliciously tampered with, or misused, potentially leading to malicious code injection, backdoors, or data leakage.",complexity:"Intermediate",influence:"Harms include potential business disruption, sensitive information exposure, and system vulnerability exposure, significantly impacting the organization's trust and reliability.",references:[{title:"Insider threat - Wikipedia"}],keywords:["Outsourced Personnel Risk","insider threat","contractor risk","vendor insider","third-party personnel","privileged contractor"]},"R0081-005":{title:"Open Source Component Poisoning Risk",definition:"Attackers publish packages containing malicious code on open source package management platforms (such as npm, PyPI, Maven, etc.) or hijack existing popular open source projects to conduct supply chain attacks against downstream users.",description:"Open source component poisoning is a rapidly growing supply chain attack method. Main techniques include: (1) Typosquatting: publishing malicious packages with names similar to popular packages to exploit developer typos. (2) Dependency confusion: exploiting package managers' preference for public repositories to publish malicious public packages with the same name as internal enterprise packages. (3) Maintainer account hijacking: obtaining popular open source project maintainer account access through social engineering or credential leakage to plant malicious code in normal updates. (4) Malicious PR merging: submitting pull requests containing hidden malicious code to popular open source projects. (5) Abandoned package takeover: taking over popular packages abandoned by their original authors and planting malicious code in new versions.",complexity:"Advanced",influence:"Large numbers of downstream projects are implanted with malicious code, sensitive data is leaked, systems are compromised, and the supply chain trust ecosystem is damaged.",references:[{title:"SLSA: Supply-chain Levels for Software Artifacts"}],keywords:["Open Source Component Poisoning Risk","typosquatting","dependency confusion","malicious package","package takeover","open source backdoor","npm malware","PyPI malware"]}},Ta=e({R0082:()=>Pa,default:()=>Ma}),Pa={title:"Employee Sabotage",definition:"The potential threat of internal employees deliberately taking malicious actions to damage the company's information systems, resources, or business activities.",description:"Scenarios may include employees deliberately deleting important data, tampering with system configurations, launching denial-of-service attacks, or intentionally spreading malware.",complexity:"Basic",influence:"Harms include data loss, system disruption, service unavailability, and negative impacts on the company's reputation.",references:[{title:"Governance Path for Advertising-Promotion Cyber Black-Grey Crime"}],keywords:["Employee Sabotage","malicious insider","disgruntled employee","insider sabotage","system sabotage","data destruction"]},Ma={R0082:Pa},Ba=e({R0083:()=>Fa,default:()=>Oa}),Fa={title:"Insufficient Employee Security Awareness",definition:"Refers to the potential threat that security incidents may occur due to unsafe behaviors by employees in their daily work due to insufficient security awareness.",description:"Scenarios may include employees falling victim to phishing attacks, using weak passwords, sharing account information, clicking on unknown links indiscriminately, failing to update patches in a timely manner, or having their accounts compromised through social engineering.",complexity:"Intermediate",influence:"Harms include theft of sensitive information, unauthorized access to company systems, data tampering, and malicious operations performed under stolen identities, posing potential threats to the company's confidentiality, integrity, and availability.",references:[{title:"Social engineering (security) - Wikipedia"}],keywords:["Insufficient Employee Security Awareness","security awareness training","phishing susceptibility","social engineering","weak password hygiene","human factor"]},Oa={R0083:Fa,"R0083-001":{title:"Employee Account Compromise",definition:"The potential threat that accounts of internal employees may be obtained and misused by unauthorized individuals or malicious parties.",description:"Scenarios may include employees falling victim to phishing attacks, using weak passwords, sharing account information, or being manipulated through social engineering, resulting in account compromise.",complexity:"Intermediate",influence:"Harms include theft of sensitive information, unauthorized access to company systems, data tampering, and malicious operations performed under stolen identities, posing potential threats to the company's confidentiality, integrity, and availability.",references:[{title:"Credential stuffing - Wikipedia"}],keywords:["Employee Account Compromise","account takeover","credential stuffing","password reuse","phishing","social engineering","ATO"]},"R0083-002":{title:"Social Engineering Risk",definition:"The potential threat that attackers use social engineering techniques to fraudulently exploit employees' trust and social connections to obtain sensitive information, steal credentials, or carry out other malicious activities, typically through false identities, impersonated communications, and social engineering tactics. In recent years, AI technologies (such as deepfake voice and video) have been used to enhance the credibility and success rate of social deception.",description:"Common employee social engineering scenarios include: identity impersonation (attackers posing as senior management, colleagues, customers, or other trusted entities via email, social media, or instant messaging to request sensitive information or specific tasks); impersonated communications (sending fake emails, messages, or documents to induce employees to click malicious links, download malicious attachments, or provide sensitive information); AI Deepfake Deception (attackers use AI voice cloning or video synthesis technology to impersonate company leaders or colleagues for phone or video scams, significantly increasing deception success rates); social media fraud (creating fake profiles mimicking colleagues or superiors to establish contact and extract sensitive information); and fake emergencies (posing as urgent situations to induce employees to provide sensitive information or perform unsafe operations without proper verification).",complexity:"Basic",influence:"Harms include but are not limited to: information leakage of sensitive data, credentials, or company secrets; network intrusion through unauthorized access; financial losses from fraudulent financial operations; and reputational damage from customer trust issues or broken business partnerships.",references:[{title:"Social engineering (security) - Wikipedia"}],keywords:["Social Engineering Risk","pretexting","impersonation attack","vishing","smishing","business email compromise","deepfake scam"]}},Da=e({R0084:()=>za,default:()=>qa}),za={title:"Phishing Attack",definition:"Phishing attack risk refers to attackers using false and deceptive means to induce individuals or organization members to provide sensitive information such as usernames, passwords, and financial information.",description:"Scenarios include impersonating legitimate emails, social media messages, or websites to trick victims into clicking malicious links, downloading malicious attachments, or entering sensitive information.",complexity:"Intermediate",influence:"Harms include personal privacy leakage, account compromise, and financial losses; for organizations, may lead to confidential information leakage, system intrusion, and reputational damage.",references:[{title:"Phishing - Wikipedia"},{title:"T1566 Phishing - MITRE ATT&CK"}],keywords:["Phishing Attack","email phishing","spear phishing","credential harvesting","clone phishing","vishing","smishing"]},qa={R0084:za,"R0084-001":{title:"AI-Enhanced Phishing Attack",definition:"Using AI technologies (large language models, deepfakes, etc.) to enhance the personalization, credibility, and scalability of phishing attacks.",description:"AI-enhanced phishing attacks involve attackers using AI technology to significantly improve the effectiveness of traditional phishing attacks. Key manifestations include: (1) Personalized phishing emails: using LLMs to automatically generate highly personalized phishing emails based on the target's social media information and work background, greatly increasing open and click rates. (2) Multilingual phishing: AI can automatically generate high-quality phishing content in multiple languages, supporting cross-border phishing attacks. (3) Voice phishing (Vishing): using AI voice cloning technology to impersonate trusted individuals in phone phishing. (4) Video phishing: using deepfake technology to impersonate others in video calls. (5) Adaptive phishing: AI-driven phishing systems that automatically adjust attack strategies based on target responses.",complexity:"Advanced",influence:"Phishing attack success rates increase significantly, traditional security awareness training becomes less effective, and organizations face greater social engineering attack risks.",references:[{title:"AI-Enhanced Phishing Threats - NCSC"}],keywords:["AI-Enhanced Phishing Attack","AI phishing","LLM phishing","deepfake phishing","multilingual phishing","adaptive phishing","vishing"]}},Ua=e({R0085:()=>Wa,default:()=>La}),Wa={title:"Ransomware Attack",definition:"The potential threat where attackers encrypt victims' data or threaten to expose their sensitive information, then demand ransom payment to unlock or withhold the data.",description:"Scenarios include using malware to infect systems, encrypting files, and then extorting victims to pay for decryption keys or to prevent information leakage.",complexity:"Advanced",influence:"Harms include data loss, system paralysis, and business disruption, potentially causing enormous financial losses, reputational damage, and legal liability for organizations.",references:[{title:"Ransomware - Wikipedia"},{title:"T1486 Data Encrypted for Impact - MITRE ATT&CK"}],keywords:["Ransomware Attack","ransomware","crypto locker","file encryption extortion","data extortion","double extortion"]},La={R0085:Wa,"R0085-001":{title:"Ransomware as a Service (RaaS)",definition:"Ransomware as a Service is a criminal business model where ransomware developers provide ransomware tools and infrastructure as a service to other criminals, sharing a percentage of the ransom.",description:"The RaaS model significantly lowers the technical barrier for ransomware attacks, enabling criminals without technical skills to launch ransomware attacks. RaaS platforms typically provide: ransomware generators, encryption/decryption tools, ransom negotiation platforms, victim management panels, and technical support services. Well-known RaaS groups include LockBit, BlackCat/ALPHV, and Cl0p. The typical RaaS business model has developers taking 20%-30% of the ransom as a platform fee, with the remainder going to the 'affiliates' who actually launch the attacks.",complexity:"Advanced",influence:"The number and frequency of ransomware attacks increase significantly, small and medium enterprises become primary targets, and ransom amounts continue to rise.",references:[{title:"Ransomware as a Service Trend Analysis"}],keywords:["Ransomware as a Service (RaaS)","RaaS","ransomware affiliate program","malware-as-a-service","extortion platform","affiliate model"]},"R0085-002":{title:"Double / Triple Extortion",definition:"In addition to encrypting data, attackers add data leakage threats (double extortion) and pressure on the victim's customers/partners (triple extortion) as multiple extortion tactics.",description:"Double/triple extortion is an escalated form of ransomware attack. (1) Double extortion: attackers steal a copy of the victim's data before encrypting it, threatening to publicly leak the data on the dark web if the victim refuses to pay. (2) Triple extortion: in addition to double extortion, attackers also contact the victim's customers, partners, or regulators to notify them of the data breach, applying additional pressure to force payment. (3) Quadruple extortion: some attackers also simultaneously launch DDoS attacks to further paralyze the victim's business systems. This multi-extortion strategy means that even comprehensive data backups cannot fully mitigate ransomware risk.",complexity:"Advanced",influence:"Data leakage risk persists even with backups, customer and partner trust is damaged, and compliance penalty risks arise.",references:[{title:"Ransomware - Wikipedia"}],keywords:["Double / Triple Extortion","double extortion","triple extortion","quadruple extortion","leak site","data theft extortion"]}},Ea=e({R0086:()=>Ga,default:()=>Ha}),Ga={title:"Server Cryptomining",definition:"Server cryptomining risk refers to the potential threat of attackers using compromised server resources without authorization to mine cryptocurrency.",description:"Scenarios include attackers infecting servers with malware and using the server's computing power for cryptocurrency mining activities.",complexity:"Intermediate",influence:"Harms include degraded server performance and increased energy consumption, potentially leading to reduced service quality, additional electricity costs, and financial and resource losses for the organization.",references:[{title:"Cryptojacking - Wikipedia"}],keywords:["Server Cryptomining","cryptojacking","unauthorized crypto mining","illicit mining","server mining","mining malware"]},Ha={R0086:Ga},ja=e({R0087:()=>Na,default:()=>Va}),Na={title:"Business Logic Tampering Risk",definition:"The potential threat of attackers modifying the runtime logic of business systems to manipulate or disrupt system functions, steal sensitive information, or carry out other malicious activities.",description:"Scenarios include attackers illegally modifying business logic, manipulating transaction processes, or tampering with data inputs, potentially causing incorrect system processing, resource abuse, or unauthorized data access.",complexity:"Advanced",influence:"Harms include business data inconsistency and compromised transaction integrity, potentially causing financial losses, loss of trust, and compliance issues for the organization.",references:[{title:"T1190 Exploit Public-Facing Application - MITRE ATT&CK"}],keywords:["Business Logic Tampering Risk","business logic abuse","parameter tampering","workflow bypass","transaction tampering","race condition","logic flaw exploitation"]},Va={R0087:Na},Ka=e({R0088:()=>Qa,default:()=>_a}),Qa={title:"Automated Login Risk",definition:"The identity authentication login process can be automated, creating security risks.",description:"Automated login risk refers to the use of automated scripts, bots, or software to execute the login process, potentially involving a range of security threats and issues.",complexity:"Intermediate",influence:"Can lead to credential cracking (R0032), credential stuffing (R0032-001), and other cyberattacks; can also be used for automated account seasoning (R0034) and third-party account aggregation (R0037), making it a priority defense target.",references:[{title:"Credential stuffing - Wikipedia"}],keywords:["Automated Login Risk","login automation","bot login","scripted login","credential stuffing","brute force login","automated sign-in"]},_a={R0088:Qa},Ya=e({R0089:()=>Ja,default:()=>Xa}),Ja={title:"User Privacy Leakage",definition:"User privacy leakage (PII leaked) refers to the potential threat to personal sensitive information stored, processed, or transmitted on a platform due to security vulnerabilities, data breaches, or misuse, causing user privacy and security issues.",description:"Causes of personal privacy leakage risk include platform security vulnerabilities, unauthorized data access, misuse of user data, and improper handling of user information by third-party partners, all of which create potential risks of user privacy exposure.",complexity:"Basic",influence:"Personal privacy leakage risk may cause users to lose trust, trigger legal liability, damage the platform's reputation, reduce user activity, and create regulatory compliance issues, negatively impacting the platform's sustainable development.",references:[{title:"Privacy breach - Wikipedia"}],keywords:["User Privacy Leakage","PII leakage","personal data breach","privacy breach","sensitive data exposure","personal information leakage"]},Xa={R0089:Ja},Za=e({R0090:()=>$a,default:()=>en}),$a={title:"Bulk Account Enumeration",definition:"Bulk account enumeration risk refers to the potential threat of attackers using automated tools to scan, verify, or obtain user account information at scale, potentially leading to user privacy leakage and account security issues.",description:"Bulk account enumeration typically involves attackers using automated tools for large-scale account scanning, with common techniques including brute force, dictionary attacks, and social engineering. Attackers may attempt to crack passwords, bypass CAPTCHAs, and abuse API interfaces to obtain large amounts of user account information. This behavior may lead to user privacy leakage, account abuse, and platform reputational damage.",complexity:"Basic",influence:"Bulk account enumeration risk may lead to large-scale user account information leakage, triggering personal privacy issues, account abuse, identity theft, and other security risks, while negatively impacting platform reputation and user trust.",references:[{title:"Credential stuffing - Wikipedia"}],keywords:["Bulk Account Enumeration","account enumeration","user enumeration","username enumeration","email enumeration","CAPTCHA bypass","credential stuffing"]},en={R0090:$a},tn=e({R0091:()=>an,default:()=>nn}),an={title:"Game Account Laundering",definition:"Stealing game account credentials through trojans or other hacking methods, then transferring in-game currency and items to the attacker via transactions for profit.",description:"Account laundering methods are varied and include but are not limited to: stealing account credentials through illegal means to log in and extract virtual items and currency; exploiting vulnerabilities in game systems or related systems to intrude into accounts; and fraud or malicious programs to deceive users into giving up credentials or to attack accounts and extract virtual assets.",complexity:"Basic",influence:"Damages the platform's gaming ecosystem and causes losses to players' virtual assets.",references:[{title:"Cheating in video games - Wikipedia"}],keywords:["Game Account Laundering","game account theft","real-money trading","RMT","virtual item resale","virtual currency theft","stolen game account"]},nn={R0091:an},on=e({R0092:()=>sn,default:()=>rn}),sn={title:"Real-World Identity Theft",definition:"Real-world identity theft risk refers to the potential threat of malicious actors obtaining others' real identity information through illegal means and using it for fraud, crime, or other unlawful activities, involving the theft and misuse of personal sensitive information that may cause serious financial losses and privacy leakage for victims.",description:"Key characteristics include: identity information theft (obtaining personal identity information such as name, ID number, address, phone number, and bank account details); fake account creation (using stolen identity information to open fake bank accounts, credit card accounts, or other financial accounts); credit card fraud; social engineering attacks to obtain additional personal information; and criminal activities such as trafficking, money laundering, and smuggling using stolen identity information.",complexity:"Basic",influence:"Real-world identity theft may cause serious multi-faceted impacts: individuals may face significant financial losses including stolen bank accounts, credit card abuse, and illegally applied loans; credit rating decline and legal liability may further burden victims; psychological impacts including loss of privacy, anxiety, and fear are significant; social trust is affected as identity theft cases increase; and financial institutions may face financial losses from fraudulent transactions and anti-fraud measures.",references:[{title:"Public Security Organs Crack Down on Personal Information Crimes — 10 Typical Cases"},{title:"Personal Information Protection Law of the People's Republic of China"}],keywords:["Real-World Identity Theft","identity theft","identity fraud","stolen identity","personal information theft","account opening fraud","impersonation fraud"]},rn={R0092:sn},cn=e({R0093:()=>ln,default:()=>dn}),ln={title:"Payment Channel Abuse",definition:"Payment channel abuse risk refers to the potential threat of malicious actors abusing payment systems or channels to obtain financial benefits through illegal means or carry out fraudulent activities, involving various aspects of the payment process including payment cards, electronic payments, online payments, and offline payments.",description:"Main aspects include: fraud risk (some bad actors may use fake accounts, forged payment documents, and other means to conduct fraudulent activities); money laundering risk (some bad actors may use payment channels to launder money, converting illegal proceeds into legitimate funds); and cross-border fund risk (cross-border fund flows may involve foreign exchange controls, tax policies, anti-money laundering requirements, and other considerations).",complexity:"Basic",influence:"Causes financial losses and security risks for merchants and consumers.",references:[{title:"Rampant Third-Party Payment Chaos: Held Accountable for Providing Unauthorized Payment Channels"}],keywords:["Payment Channel Abuse","payment fraud","third-party payment","payment laundering","money mule","merchant fraud","payment processor abuse"]},dn={R0093:ln},un=e({R0094:()=>pn,default:()=>mn}),pn={title:"Credit Card Fraud",definition:"Credit card fraud refers to the intentional use of forged or invalid credit cards, impersonating another person's credit card to obtain property, or maliciously overdrawing one's own credit card.",description:"Common fraud forms include: lost card misuse (cards lost in transit from the issuing bank, lost due to cardholder negligence, or stolen by criminals); fraudulent applications (using others' personal information to apply for credit cards, or deliberately providing false information such as forged ID cards or fake employer/home addresses); and counterfeit credit cards (over 60% of international credit card fraud cases involve counterfeit cards, typically organized gang operations covering data theft, card manufacturing, card trafficking, and card misuse, often using the latest technology to steal real card data). With the popularity of online payments, Card-Not-Present (CNP) fraud has become the most prevalent form of credit card fraud, where attackers use stolen card numbers and CVVs to make purchases on e-commerce platforms. Additionally, Account Takeover (ATO) attacks are increasing, where attackers obtain cardholders' online banking credentials through phishing or credential stuffing, then modify account information to commit fraud.",complexity:"Basic",influence:"Causes serious harm to individuals and society, including infringement of consumer rights, disruption of market order, and damage to financial stability.",references:[{title:"FBI Internet Crime Report 2024 - IC3 Annual Report"}],keywords:["Credit Card Fraud","carding","card-not-present fraud","CNP fraud","stolen card","chargeback fraud","carding attack"]},mn={R0094:pn},gn=e({R0095:()=>fn,default:()=>hn}),fn={title:"Platform Fraud Risk",definition:"Using platform features such as content publishing, comments, and instant messaging, or exploiting platform vulnerabilities, to conduct telecommunications fraud.",description:"Possible scenarios include: false information publishing (attackers using user-generated content features to post fake product listings, lottery notifications, or job postings to lure users into fraud); impersonating official accounts or verified users to deceive users into providing personal information, assets, or sensitive data; abusing advertising platforms to publish fake ads directing users to fraudulent sites; social engineering via private messages, comments, or invitations to induce users to click links, provide personal information, or make transfers; and exploiting platform vulnerabilities to bypass security measures and conduct fraud.",complexity:"Basic",influence:"Leads to user information leakage, financial losses, and damage to the platform's reputation and credibility.",references:[{title:"Anti-Telecom and Online Fraud Law of the PRC"},{title:"2025 Edition Anti-Telecom and Online Fraud Prevention Handbook"}],keywords:["Platform Fraud Risk","online scam","platform scam","fake listings","impersonation scam","ad fraud","marketplace fraud"]},hn={R0095:fn},yn=e({R0096:()=>bn,default:()=>kn}),bn={title:"Platform Online Loan Fraud",definition:"Online loan fraud generally refers to internet black/grey market actors using illegal means such as forged identity documents, fabricated credit materials, and purchased illegal data to exploit loopholes in internet loan approval systems during the qualification review stage, illegally obtaining loan qualifications from internet lending platforms, transferring the funds to personal accounts, and refusing to repay the loans.",description:'Main fraud methods include: registering large numbers of phone numbers and using them for bulk consumption to artificially boost credit ratings; using technical means to forge identity information, device information, and location information to obtain loans and evade post-loan collection; and exploiting the slow update cycle of public credit information to simultaneously apply for loans from multiple platforms, maliciously exhausting credit. Recent variants also include using real retroactive social insurance or housing fund contributions to create a false appearance of repayment ability and obtain consumer loan limits. Recent variants also include the professional debt bearer model, where black market groups specifically find creditworthy "blank slate" users (such as recent college graduates), fabricate income and bank statements to help them fraudulently obtain loans from multiple platforms, with the loan proceeds taken by the black market and the debt left on the debt bearers.',complexity:"Basic",influence:"Causes financial losses to the platform.",references:[{title:"Identity theft - Wikipedia"}],keywords:["Platform Online Loan Fraud","loan fraud","online loan scam","lending fraud","fake loan application","credit fraud","loan application fraud"]},kn={R0096:bn,"R0096-001":{title:"Anti-Collection Risk",definition:"Anti-collection generally refers to organizations or individuals using abnormal means to help debtors maliciously evade debts, extending repayment periods, reducing or waiving interest, or otherwise reducing debtors' repayment obligations.",description:"For example, anti-collection intermediaries have debtors forward their phone cards or set up call forwarding, so that the anti-collection gang's so-called legal staff negotiate on behalf of the debtor to achieve interest reduction and deferred/installment repayment, ultimately charging the debtor a percentage fee based on the anti-collection outcome.",complexity:"Basic",influence:"Causes financial losses to the platform.",references:[{title:"Heavy Crackdown on Financial Black-Grey Market: Multiple Institutions Help Solve Anti-Collection Cases"}],keywords:["Anti-Collection Risk","debt collection evasion","loan repayment evasion","collection avoidance","debt avoidance","anti-collection"]}},vn=e({R0097:()=>wn,default:()=>Rn}),wn={title:"Platform-Facilitated Gambling",definition:"Criminals using a platform's normal user interaction features to conduct gambling activities.",description:"WeChat group red packet gambling is a common form where criminals create multiple group chats and conduct gambling through the red packet grabbing feature. Live stream gambling exploits interactive features of live streaming platforms to attract viewers into streams where hosts play games or take bets. Social media gambling is more covert, with criminals posting false information or posing as ordinary users to attract others into gambling activities.",complexity:"Basic",influence:"Platform compliance risks and user financial losses.",references:[{title:"MPS Crackdown on Cross-Border Gambling"}],keywords:["Platform-Facilitated Gambling","online gambling","illegal betting","live stream gambling","red packet gambling","social media gambling","gambling promotion"]},Rn={R0097:wn},An=e({R0098:()=>xn,default:()=>Cn}),xn={title:"Fake Identity Authentication",definition:"A fake identity refers to a person or entity using fictitious or forged identity information to conceal their true identity or purpose.",description:"This may include using false names, addresses, dates of birth, social security numbers, and other personal information. Fake identities are typically used to deceive, evade legal liability, commit fraud, carry out cyberattacks, or engage in other improper activities.",complexity:"Basic",influence:"Affects the platform's compliance, security, credibility, user experience, and business operations.",references:[{title:"Know your customer - Wikipedia"}],keywords:["Fake Identity Authentication","fake KYC","KYC bypass","identity spoofing","forged identity","fake ID","identity verification fraud"]},Cn={R0098:xn},Sn=e({R0099:()=>In,default:()=>Tn}),In={title:"Blocklisted IP Bypass",definition:"Attackers using various means to evade or bypass a system's mechanisms for identifying and blocking blocklisted IP addresses. Blocklisted IPs typically contain known malicious IP addresses that the system uses to identify and block potential threats.",description:"Methods used for blocklisted IP bypass include: IP address rotation (frequently changing IP addresses to avoid being blocklisted); proxy servers and VPNs (hiding the real IP address and appearing to come from different locations); TOR network (routing traffic through multiple nodes to hide the real IP); botnets (using multiple infected computers with different IP addresses to increase detection difficulty); low-frequency attacks (reducing attack frequency to evade detection); and IP spoofing (disguising the real IP address to appear as legitimate traffic).",complexity:"Basic",influence:"Blocking becomes ineffective if the blocklist cannot be updated in time; legitimate users may be falsely blocked if they use proxies or VPNs; deploying complex blocklist mechanisms may increase system load and be exploited for denial-of-service attacks.",references:[{title:"Proxy server - Wikipedia"}],keywords:["Blocklisted IP Bypass","blacklist evasion","IP rotation","proxy rotation","VPN evasion","Tor bypass","botnet IPs"]},Tn={R0099:In};export{Bi as $,Kt as A,K as At,ht as B,h as Bt,ma as C,me as Ct,ia as D,ie as Dt,na as E,ne as Et,Bt as F,B as Ft,it as G,i as Gt,dt as H,d as Ht,Tt as I,T as It,Ki as J,Zi as K,Ct as L,C as Lt,Et as M,E as Mt,Ut as N,U as Nt,Zt as O,Z as Ot,Dt as P,D as Pt,Di as Q,Rt as R,R as Rt,ha as S,he as St,ra as T,re as Tt,rt as U,r as Ut,mt as V,m as Vt,nt as W,n as Wt,Ei as X,ji as Y,Ui as Z,Ba as _,Be as _t,gn as a,mi as at,Ra as b,Re as bt,on as c,ni as ct,Ya as d,Ye as dt,Ti as et,Ka as f,Ke as ft,Da as g,De as gt,Ua as h,Ue as ht,yn as i,hi as it,jt as j,j as jt,Yt as k,Y as kt,tn as l,ii as lt,Ea as m,Ee as mt,An as n,Ri as nt,un as o,di as ot,ja as p,je as pt,Yi as q,vn as r,ki as rt,cn as s,ri as st,Sn as t,Ci as tt,Za as u,Ze as ut,Ta as v,Te as vt,da as w,de as wt,ka as x,ke as xt,Ca as y,Ce as yt,kt as z,k as zt};